    function toString(uint256 value) internal pure returns (string memory) {
        unchecked {
            uint256 length = Math.log10(value) + 1;
            string memory buffer = new string(length);
            uint256 ptr;
            /// @solidity memory-safe-assembly
            assembly {
                ptr := add(buffer, add(32, length))
            }
            while (true) {
                ptr--;
                /// @solidity memory-safe-assembly
                assembly {
                    mstore8(ptr, byte(mod(value, 10), _SYMBOLS))
                }
                value /= 10;
                if (value == 0) break;
            }
            return buffer;
        }
    }

    /**
     * @dev Converts a `int256` to its ASCII `string` decimal representation.
     */
    function toString(int256 value) internal pure returns (string memory) {
        return string(abi.encodePacked(value < 0 ? "-" : "", toString(SignedMath.abs(value))));
    }

    /**
     * @dev Converts a `uint256` to its ASCII `string` hexadecimal representation.
     */
    function toHexString(uint256 value) internal pure returns (string memory) {
        unchecked {
            return toHexString(value, Math.log256(value) + 1);
        }
    }

    /**
     * @dev Converts a `uint256` to its ASCII `string` hexadecimal representation with fixed length.
     */
    function toHexString(uint256 value, uint256 length) internal pure returns (string memory) {
        bytes memory buffer = new bytes(2 * length + 2);
        buffer[0] = "0";
        buffer[1] = "x";
        for (uint256 i = 2 * length + 1; i > 1; --i) {
            buffer[i] = _SYMBOLS[value & 0xf];
            value >>= 4;
        }
        require(value == 0, "Strings: hex length insufficient");
        return string(buffer);
    }

    /**
     * @dev Converts an `address` with fixed length of 20 bytes to its not checksummed ASCII `string` hexadecimal representation.
     */
    function toHexString(address addr) internal pure returns (string memory) {
        return toHexString(uint256(uint160(addr)), _ADDRESS_LENGTH);
    }

    /**
     * @dev Returns true if the two strings are equal.
     */
    function equal(string memory a, string memory b) internal pure returns (bool) {
        return keccak256(bytes(a)) == keccak256(bytes(b));
    }
}

contracts/AssetBackedExchange.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title AssetBackedExchange
 * @notice Decentralized exchange for trading asset-backed security tokens
 *         against ETH (native), WETH, WBTC, and any ERC-20 token.
 *
 *         Supports:
 *         - Limit orders (token/token)
 *         - ETH-based orders (buy or sell with native ETH)
 *         - Partial fills
 *         - Order cancellation
 *
 * @dev Uses a pull-based pattern for ETH refunds to prevent reentrancy.
 *      All ERC-20 interactions use the standard interface.
 */

interface IERC20 {
    function totalSupply() external view returns (uint256);
    function balanceOf(address account) external view returns (uint256);
    function transfer(address to, uint256 amount) external returns (bool);
    function allowance(address owner, address spender) external view returns (uint256);
    function approve(address spender, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
}

contract AssetBackedExchange {

    // ---------------------------------------------------------------
    //  Constants
    // ---------------------------------------------------------------

    /// @notice Sentinel address representing native ETH in order pairs.
    address public constant ETH_ADDRESS = 0xEeeeeEeeeEeEeeEeEeEeeEEEeeeeEeeeeeeeEEeE;

    // ---------------------------------------------------------------
    //  Storage
    // ---------------------------------------------------------------

    struct Order {
        uint256 id;
        address maker;
        address tokenSell;     // what the maker is selling (ETH_ADDRESS for native ETH)
        address tokenBuy;      // what the maker wants to buy (ETH_ADDRESS for native ETH)
        uint256 amountSell;    // total sell amount
        uint256 amountBuy;     // total buy amount (price = amountBuy/amountSell)
        uint256 filledSell;    // amount already filled on sell side
        uint256 filledBuy;     // amount already filled on buy side
        bool    cancelled;
    }

    uint256 public nextOrderId;
    mapping(uint256 => Order) private _orders;

    /// @notice maker address => array of their order IDs
    mapping(address => uint256[]) private _userOrderIds;

    /// @notice Refundable ETH balances (for cancelled ETH-sell orders)
    mapping(address => uint256) public ethBalances;

    // ---------------------------------------------------------------
    //  Events
    // ---------------------------------------------------------------

    event OrderCreated(
        uint256 indexed orderId,
        address indexed maker,
        address tokenSell,
        address tokenBuy,
        uint256 amountSell,
        uint256 amountBuy
    );

    event OrderFilled(
        uint256 indexed orderId,
        address indexed taker,
        uint256 fillAmountSell,
        uint256 fillAmountBuy
    );

    event OrderCancelled(uint256 indexed orderId, address indexed maker);

    event EthWithdrawn(address indexed to, uint256 amount);

    // ---------------------------------------------------------------
    //  Errors
    // ---------------------------------------------------------------

    error ZeroAmount();
    error ZeroAddress();
    error SameToken();
    error OrderNotActive();
    error NotMaker();
    error InsufficientFill();
    error TransferFailed();
    error InsufficientEth();
    error NothingToWithdraw();

    // ---------------------------------------------------------------
    //  Create order
    // ---------------------------------------------------------------

    /**
     * @notice Create a limit order to sell an ERC-20 token.
     *         For selling native ETH, use createOrderSellETH instead.
     *
     * @param tokenSell  The ERC-20 token being sold
     * @param tokenBuy   The token wanted in return (ETH_ADDRESS for native ETH)
     * @param amountSell Amount of tokenSell to offer
     * @param amountBuy  Amount of tokenBuy desired (sets the price)
     */
    function createOrder(
        address tokenSell,
        address tokenBuy,
        uint256 amountSell,
        uint256 amountBuy
    ) external returns (uint256 orderId) {
        if (amountSell == 0 || amountBuy == 0) revert ZeroAmount();
        if (tokenSell == address(0) || tokenBuy == address(0)) revert ZeroAddress();
        if (tokenSell == tokenBuy) revert SameToken();
        if (tokenSell == ETH_ADDRESS) revert ZeroAddress(); // use createOrderSellETH

        // Transfer sell tokens to this contract
        bool ok = IERC20(tokenSell).transferFrom(msg.sender, address(this), amountSell);
        if (!ok) revert TransferFailed();

        orderId = _createOrder(msg.sender, tokenSell, tokenBuy, amountSell, amountBuy);
    }

    /**
     * @notice Create a limit order selling native ETH for an ERC-20 token.
     *
     * @param tokenBuy   The ERC-20 token wanted in return
     * @param amountBuy  Amount of tokenBuy desired
     */
    function createOrderSellETH(
        address tokenBuy,
        uint256 amountBuy
    ) external payable returns (uint256 orderId) {
        if (msg.value == 0 || amountBuy == 0) revert ZeroAmount();
        if (tokenBuy == address(0) || tokenBuy == ETH_ADDRESS) revert ZeroAddress();

        orderId = _createOrder(msg.sender, ETH_ADDRESS, tokenBuy, msg.value, amountBuy);
    }

    function _createOrder(
        address maker,
        address tokenSell,
        address tokenBuy,
        uint256 amountSell,
        uint256 amountBuy
    ) private returns (uint256 orderId) {
        orderId = nextOrderId++;

        _orders[orderId] = Order({
            id: orderId,
            maker: maker,
            tokenSell: tokenSell,
            tokenBuy: tokenBuy,
            amountSell: amountSell,
            amountBuy: amountBuy,
            filledSell: 0,
            filledBuy: 0,
            cancelled: false
        });

        _userOrderIds[maker].push(orderId);

        emit OrderCreated(orderId, maker, tokenSell, tokenBuy, amountSell, amountBuy);
    }

    // ---------------------------------------------------------------
    //  Fill order
    // ---------------------------------------------------------------

    /**
     * @notice Fill an existing order by providing the buy-side token.
     *         For orders where tokenBuy is ETH, use fillOrderWithETH.
     *
     * @param orderId       The order to fill
     * @param fillAmountBuy Amount of the buy token to provide
     */
    function fillOrder(uint256 orderId, uint256 fillAmountBuy) external {
        Order storage order = _orders[orderId];
        _validateOrderActive(order);
        if (fillAmountBuy == 0) revert ZeroAmount();
        if (order.tokenBuy == ETH_ADDRESS) revert ZeroAddress(); // use fillOrderWithETH

        uint256 remainingBuy = order.amountBuy - order.filledBuy;
        if (fillAmountBuy > remainingBuy) fillAmountBuy = remainingBuy;

        // Calculate proportional sell amount
        uint256 fillAmountSell = (fillAmountBuy * order.amountSell) / order.amountBuy;
        if (fillAmountSell == 0) revert InsufficientFill();

        order.filledBuy += fillAmountBuy;
        order.filledSell += fillAmountSell;

        // Taker sends buy tokens to maker
        bool ok = IERC20(order.tokenBuy).transferFrom(msg.sender, order.maker, fillAmountBuy);
        if (!ok) revert TransferFailed();

        // Taker receives sell tokens from escrow
        if (order.tokenSell == ETH_ADDRESS) {
            (bool sent,) = payable(msg.sender).call{value: fillAmountSell}("");
            if (!sent) revert TransferFailed();
        } else {
            ok = IERC20(order.tokenSell).transfer(msg.sender, fillAmountSell);
            if (!ok) revert TransferFailed();
        }

        emit OrderFilled(orderId, msg.sender, fillAmountSell, fillAmountBuy);
    }

    /**
     * @notice Fill an order where the buy-side is native ETH.
     *
     * @param orderId The order to fill
     */
    function fillOrderWithETH(uint256 orderId) external payable {
        Order storage order = _orders[orderId];
        _validateOrderActive(order);
        if (msg.value == 0) revert ZeroAmount();
        if (order.tokenBuy != ETH_ADDRESS) revert ZeroAddress(); // use fillOrder

        uint256 remainingBuy = order.amountBuy - order.filledBuy;
        uint256 fillAmountBuy = msg.value > remainingBuy ? remainingBuy : msg.value;

        // Calculate proportional sell amount
        uint256 fillAmountSell = (fillAmountBuy * order.amountSell) / order.amountBuy;
        if (fillAmountSell == 0) revert InsufficientFill();

        order.filledBuy += fillAmountBuy;
        order.filledSell += fillAmountSell;

        // Send ETH to maker
        (bool sentToMaker,) = payable(order.maker).call{value: fillAmountBuy}("");
        if (!sentToMaker) revert TransferFailed();

        // Send sell tokens to taker
        bool ok = IERC20(order.tokenSell).transfer(msg.sender, fillAmountSell);
        if (!ok) revert TransferFailed();

        // Refund excess ETH to taker
        if (msg.value > fillAmountBuy) {
            (bool refund,) = payable(msg.sender).call{value: msg.value - fillAmountBuy}("");
            if (!refund) revert TransferFailed();
        }

        emit OrderFilled(orderId, msg.sender, fillAmountSell, fillAmountBuy);
    }

    // ---------------------------------------------------------------
    //  Cancel order
    // ---------------------------------------------------------------

    /**
     * @notice Cancel an open order and return unfilled tokens to the maker.
     */
    function cancelOrder(uint256 orderId) external {
        Order storage order = _orders[orderId];
        _validateOrderActive(order);
        if (msg.sender != order.maker) revert NotMaker();

        order.cancelled = true;

        // Return unfilled sell tokens
        uint256 remaining = order.amountSell - order.filledSell;
        if (remaining > 0) {
            if (order.tokenSell == ETH_ADDRESS) {
                // Credit ETH balance for pull-based withdrawal
                ethBalances[order.maker] += remaining;
            } else {
                bool ok = IERC20(order.tokenSell).transfer(order.maker, remaining);
                if (!ok) revert TransferFailed();
            }
        }

        emit OrderCancelled(orderId, msg.sender);
    }

    /**
     * @notice Withdraw credited ETH (from cancelled ETH-sell orders).
     */
    function withdrawEth() external {
        uint256 balance = ethBalances[msg.sender];
        if (balance == 0) revert NothingToWithdraw();
        ethBalances[msg.sender] = 0;

        (bool sent,) = payable(msg.sender).call{value: balance}("");
        if (!sent) revert TransferFailed();

        emit EthWithdrawn(msg.sender, balance);
    }

    // ---------------------------------------------------------------
    //  View functions
    // ---------------------------------------------------------------

    function getOrder(uint256 orderId) external view returns (Order memory) {
        return _orders[orderId];
    }

    function getUserOrders(address user) external view returns (uint256[] memory) {
        return _userOrderIds[user];
    }

    function getOrderCount() external view returns (uint256) {
        return nextOrderId;
    }

    /**
     * @notice Get all active (non-cancelled, not fully filled) orders
     *         for a specific trading pair.
     */
    function getActiveOrders(
        address tokenSell,
        address tokenBuy
    ) external view returns (Order[] memory) {
        // Count matching orders first
        uint256 count = 0;
        for (uint256 i = 0; i < nextOrderId; i++) {
            Order storage o = _orders[i];
            if (o.tokenSell == tokenSell &&
                o.tokenBuy == tokenBuy &&
                !o.cancelled &&
                o.filledSell < o.amountSell) {
                count++;
            }
        }

        // Build result array
        Order[] memory result = new Order[](count);
        uint256 idx = 0;
        for (uint256 i = 0; i < nextOrderId; i++) {
            Order storage o = _orders[i];
            if (o.tokenSell == tokenSell &&
                o.tokenBuy == tokenBuy &&
                !o.cancelled &&
                o.filledSell < o.amountSell) {
                result[idx++] = o;
            }
        }
        return result;
    }

    // ---------------------------------------------------------------
    //  Internal
    // ---------------------------------------------------------------

    function _validateOrderActive(Order storage order) private view {
        if (order.cancelled) revert OrderNotActive();
        if (order.filledSell >= order.amountSell) revert OrderNotActive();
    }

    // ---------------------------------------------------------------
    //  Receive ETH
    // ---------------------------------------------------------------

    receive() external payable {}
}

contracts/AssetExchange.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title AssetExchange
 * @notice A fully on-chain limit-order book for ERC-20 token pairs.
 *
 *         Makers create orders specifying the tokens and amounts they wish to
 *         swap.  Takers fill orders by providing the requested buy-side tokens
 *         and receiving the sell-side tokens held in escrow.
 *
 *         Orders can be partially filled.  Makers may cancel any unfilled
 *         portion of their orders at any time.
 *
 * @dev    Implements a manual reentrancy guard (no external imports).
 *         All token transfers use a safe low-level call wrapper that reverts
 *         on failure, defending against non-compliant ERC-20 implementations.
 */
contract AssetExchange {

    // ---------------------------------------------------------------
    //  Reentrancy guard
    // ---------------------------------------------------------------

    uint256 private constant _NOT_ENTERED = 1;
    uint256 private constant _ENTERED     = 2;
    uint256 private _status = _NOT_ENTERED;

    modifier nonReentrant() {
        if (_status == _ENTERED) revert ReentrancyDetected();
        _status = _ENTERED;
        _;
        _status = _NOT_ENTERED;
    }

    // ---------------------------------------------------------------
    //  Data structures
    // ---------------------------------------------------------------

    struct Order {
        uint256 id;
        address maker;
        address tokenSell;
        address tokenBuy;
        uint256 amountSell;      // total sell-side amount committed
        uint256 amountBuy;       // total buy-side amount requested
        uint256 filledSell;      // cumulative sell-side tokens transferred out
        uint256 filledBuy;       // cumulative buy-side tokens received by maker
        bool    cancelled;
    }

    // ---------------------------------------------------------------
    //  Storage
    // ---------------------------------------------------------------

    /// @notice Auto-incrementing order counter. First valid id is 1.
    uint256 public nextOrderId = 1;

    /// @notice orderId => Order
    mapping(uint256 => Order) public orders;

    /// @notice Ordered pair key => array of order ids that belong to this pair.
    ///         The key is `keccak256(abi.encodePacked(tokenSell, tokenBuy))`.
    mapping(bytes32 => uint256[]) private _pairOrderIds;

    // ---------------------------------------------------------------
    //  Events
    // ---------------------------------------------------------------

    event OrderCreated(
        uint256 indexed orderId,
        address indexed maker,
        address         tokenSell,
        address         tokenBuy,
        uint256         amountSell,
        uint256         amountBuy
    );

    event OrderFilled(
        uint256 indexed orderId,
        address indexed taker,
        uint256         fillAmountSell,
        uint256         fillAmountBuy
    );

    event OrderCancelled(
        uint256 indexed orderId,
        address indexed maker
    );

    // ---------------------------------------------------------------
    //  Errors
    // ---------------------------------------------------------------

    error ReentrancyDetected();
    error ZeroAddress();
    error ZeroAmount();
    error SameToken();
    error OrderDoesNotExist();
    error OrderAlreadyCancelled();
    error OrderFullyFilled();
    error NotOrderMaker();
    error FillAmountTooLarge();
    error TransferFailed();

    // ---------------------------------------------------------------
    //  External: create order
    // ---------------------------------------------------------------

    /**
     * @notice Create a new limit order.
     *
     *         The maker commits `amountSell` of `tokenSell` (transferred into
     *         escrow immediately) and requests `amountBuy` of `tokenBuy` in
     *         return.
     *
     * @param tokenSell  Address of the ERC-20 being sold.
     * @param tokenBuy   Address of the ERC-20 being bought.
     * @param amountSell Total sell-side amount to escrow.
     * @param amountBuy  Total buy-side amount desired.
     *
     * @return orderId   The id of the newly created order.
     */
    function createOrder(
        address tokenSell,
        address tokenBuy,
        uint256 amountSell,
        uint256 amountBuy
    ) external nonReentrant returns (uint256 orderId) {
        if (tokenSell == address(0) || tokenBuy == address(0)) revert ZeroAddress();
        if (tokenSell == tokenBuy) revert SameToken();
        if (amountSell == 0 || amountBuy == 0) revert ZeroAmount();

        orderId = nextOrderId++;

        orders[orderId] = Order({
            id:         orderId,
            maker:      msg.sender,
            tokenSell:  tokenSell,
            tokenBuy:   tokenBuy,
            amountSell: amountSell,
            amountBuy:  amountBuy,
            filledSell: 0,
            filledBuy:  0,
            cancelled:  false
        });

        bytes32 pairKey = _pairKey(tokenSell, tokenBuy);
        _pairOrderIds[pairKey].push(orderId);

        // Transfer sell tokens from maker into this contract (escrow).
        _safeTransferFrom(tokenSell, msg.sender, address(this), amountSell);

        emit OrderCreated(orderId, msg.sender, tokenSell, tokenBuy, amountSell, amountBuy);
    }

    // ---------------------------------------------------------------
    //  External: fill order
    // ---------------------------------------------------------------

    /**
     * @notice Fill (partially or fully) an existing order.
     *
     *         The taker sends `fillAmountBuy` of the order's `tokenBuy` to the
     *         maker.  In return the taker receives the proportional amount of
     *         the order's `tokenSell` from escrow.
     *
     *         The proportional sell amount is:
     *             fillAmountSell = fillAmountBuy * amountSell / amountBuy
     *
     * @param orderId      The order to fill.
     * @param fillAmountBuy Amount of tokenBuy the taker is providing.
     */
    function fillOrder(
        uint256 orderId,
        uint256 fillAmountBuy
    ) external nonReentrant {
        Order storage order = orders[orderId];
        if (order.maker == address(0)) revert OrderDoesNotExist();
        if (order.cancelled) revert OrderAlreadyCancelled();
        if (fillAmountBuy == 0) revert ZeroAmount();

        uint256 remainingBuy = order.amountBuy - order.filledBuy;
        if (remainingBuy == 0) revert OrderFullyFilled();
        if (fillAmountBuy > remainingBuy) revert FillAmountTooLarge();

        // Calculate the proportional sell amount.
        // Using full-precision multiplication then division to minimize rounding.
        uint256 fillAmountSell = (fillAmountBuy * order.amountSell) / order.amountBuy;
        if (fillAmountSell == 0) revert ZeroAmount();

        // Update state before external calls (checks-effects-interactions).
        order.filledBuy  += fillAmountBuy;
        order.filledSell += fillAmountSell;

        // Taker sends buy-side tokens to the maker.
        _safeTransferFrom(order.tokenBuy, msg.sender, order.maker, fillAmountBuy);

        // Contract sends escrowed sell-side tokens to the taker.
        _safeTransfer(order.tokenSell, msg.sender, fillAmountSell);

        emit OrderFilled(orderId, msg.sender, fillAmountSell, fillAmountBuy);
    }

    // ---------------------------------------------------------------
    //  External: cancel order
    // ---------------------------------------------------------------

    /**
     * @notice Cancel an open order. Only the original maker may cancel.
     *         Any un-filled sell-side tokens are returned from escrow to
     *         the maker.
     *
     * @param orderId The order to cancel.
     */
    function cancelOrder(uint256 orderId) external nonReentrant {
        Order storage order = orders[orderId];
        if (order.maker == address(0)) revert OrderDoesNotExist();
        if (order.cancelled) revert OrderAlreadyCancelled();
        if (order.maker != msg.sender) revert NotOrderMaker();

        order.cancelled = true;

        // Refund un-filled sell tokens.
        uint256 remaining = order.amountSell - order.filledSell;
        if (remaining > 0) {
            _safeTransfer(order.tokenSell, msg.sender, remaining);
        }

        emit OrderCancelled(orderId, msg.sender);
    }

    // ---------------------------------------------------------------
    //  View: order queries
    // ---------------------------------------------------------------

    /**
     * @notice Return all *active* (not cancelled, not fully filled) order ids
     *         for the directed pair (tokenSell => tokenBuy).
     *
     * @param tokenSell Sell-side token address.
     * @param tokenBuy  Buy-side token address.
     *
     * @return activeOrders Array of Order structs that are still active.
     */
    function getOrders(
        address tokenSell,
        address tokenBuy
    ) external view returns (Order[] memory activeOrders) {
        bytes32 pairKey = _pairKey(tokenSell, tokenBuy);
        uint256[] storage ids = _pairOrderIds[pairKey];
        uint256 len = ids.length;

        // First pass: count active orders so we can size the return array.
        uint256 count;
        for (uint256 i; i < len; ++i) {
            Order storage o = orders[ids[i]];
            if (!o.cancelled && o.filledBuy < o.amountBuy) {
                ++count;
            }
        }

        // Second pass: populate the return array.
        activeOrders = new Order[](count);
        uint256 idx;
        for (uint256 i; i < len; ++i) {
            Order storage o = orders[ids[i]];
            if (!o.cancelled && o.filledBuy < o.amountBuy) {
                activeOrders[idx++] = o;
            }
        }
    }

    /**
     * @notice Retrieve a single order by its id.
     * @param orderId The order id.
     */
    function getOrder(uint256 orderId) external view returns (Order memory) {
        if (orders[orderId].maker == address(0)) revert OrderDoesNotExist();
        return orders[orderId];
    }

    // ---------------------------------------------------------------
    //  Internal helpers
    // ---------------------------------------------------------------

    /**
     * @dev Deterministic key for a directed token pair.
     *      (tokenA, tokenB) and (tokenB, tokenA) produce *different* keys.
     *      This is intentional: sell orders A->B are conceptually distinct
     *      from sell orders B->A.
     */
    function _pairKey(address tokenA, address tokenB) internal pure returns (bytes32) {
        return keccak256(abi.encodePacked(tokenA, tokenB));
    }

    /**
     * @dev Safely call `IERC20.transferFrom(from, to, amount)`.
     *      Handles tokens that return bool as well as tokens that return
     *      nothing (USDT-style).
     */
    function _safeTransferFrom(
        address token,
        address from,
        address to,
        uint256 amount
    ) internal {
        (bool success, bytes memory data) = token.call(
            abi.encodeWithSelector(
                // bytes4(keccak256("transferFrom(address,address,uint256)"))
                0x23b872dd,
                from,
                to,
                amount
            )
        );
        if (!success || (data.length > 0 && !abi.decode(data, (bool)))) {
            revert TransferFailed();
        }
    }

    /**
     * @dev Safely call `IERC20.transfer(to, amount)`.
     */
    function _safeTransfer(
        address token,
        address to,
        uint256 amount
    ) internal {
        (bool success, bytes memory data) = token.call(
            abi.encodeWithSelector(
                // bytes4(keccak256("transfer(address,uint256)"))
                0xa9059cbb,
                to,
                amount
            )
        );
        if (!success || (data.length > 0 && !abi.decode(data, (bool)))) {
            revert TransferFailed();
        }
    }
}

contracts/LiquidityPoolAMM.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title LiquidityPoolAMM
 * @notice Uniswap V2-style constant product AMM (x * y = k) for trading
 *         asset-backed tokens and native ETH.
 *
 *         Features:
 *         - Permissionless pool creation for any token pair
 *         - Constant product pricing with 0.3% swap fee
 *         - Add/remove liquidity with proportional LP shares
 *         - Native ETH support via sentinel address
 *         - Pull-based ETH withdrawal pattern
 *
 * @dev Follows existing platform conventions: no OpenZeppelin imports,
 *      manual reentrancy guard, custom errors, ETH sentinel address.
 */

interface IERC20 {
    function totalSupply() external view returns (uint256);
    function balanceOf(address account) external view returns (uint256);
    function transfer(address to, uint256 amount) external returns (bool);
    function allowance(address owner, address spender) external view returns (uint256);
    function approve(address spender, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
}

contract LiquidityPoolAMM {

    // ---------------------------------------------------------------
    //  Constants
    // ---------------------------------------------------------------

    /// @notice Sentinel address representing native ETH in pools.
    address public constant ETH_ADDRESS = 0xEeeeeEeeeEeEeeEeEeEeeEEEeeeeEeeeeeeeEEeE;

    /// @notice Minimum liquidity burned on first deposit to prevent division by zero.
    uint256 public constant MINIMUM_LIQUIDITY = 1000;

    /// @notice Swap fee numerator (3 = 0.3%).
    uint256 public constant FEE_NUMERATOR = 3;

    /// @notice Swap fee denominator.
    uint256 public constant FEE_DENOMINATOR = 1000;

    // ---------------------------------------------------------------
    //  Storage
    // ---------------------------------------------------------------

    struct Pool {
        address token0;
        address token1;
        uint256 reserve0;
        uint256 reserve1;
        uint256 totalLiquidity;
        uint256 kLast;
    }

    /// @notice poolId = keccak256(abi.encodePacked(sortedToken0, sortedToken1))
    mapping(bytes32 => Pool) public pools;

    /// @notice LP balances: poolId => (provider => liquidity)
    mapping(bytes32 => mapping(address => uint256)) public liquidityBalances;

    /// @notice Withdrawable ETH balances (pull pattern)
    mapping(address => uint256) public ethBalances;

    /// @notice Reentrancy guard status
    uint256 private _status;
    uint256 private constant _NOT_ENTERED = 1;
    uint256 private constant _ENTERED = 2;

    // ---------------------------------------------------------------
    //  Events
    // ---------------------------------------------------------------

    event PoolCreated(
        bytes32 indexed poolId,
        address indexed token0,
        address indexed token1
    );

    event LiquidityAdded(
        bytes32 indexed poolId,
        address indexed provider,
        uint256 amount0,
        uint256 amount1,
        uint256 liquidity
    );

    event LiquidityRemoved(
        bytes32 indexed poolId,
        address indexed provider,
        uint256 amount0,
        uint256 amount1,
        uint256 liquidity
    );

    event Swap(
        bytes32 indexed poolId,
        address indexed sender,
        address tokenIn,
        address tokenOut,
        uint256 amountIn,
        uint256 amountOut
    );

    event EthWithdrawn(address indexed to, uint256 amount);

    // ---------------------------------------------------------------
    //  Errors
    // ---------------------------------------------------------------

    error ZeroAmount();
    error ZeroAddress();
    error SameToken();
    error PoolExists();
    error PoolNotFound();
    error InsufficientLiquidity();
    error InsufficientOutput();
    error InsufficientAAmount();
    error InsufficientBAmount();
    error TransferFailed();
    error InsufficientEth();
    error NothingToWithdraw();
    error ReentrantCall();
    error InvalidK();

    // ---------------------------------------------------------------
    //  Modifiers
    // ---------------------------------------------------------------

    modifier nonReentrant() {
        if (_status == _ENTERED) revert ReentrantCall();
        _status = _ENTERED;
        _;
        _status = _NOT_ENTERED;
    }

    // ---------------------------------------------------------------
    //  Constructor
    // ---------------------------------------------------------------

    constructor() {
        _status = _NOT_ENTERED;
    }

    // ---------------------------------------------------------------
    //  Pool creation
    // ---------------------------------------------------------------

    /**
     * @notice Create a new liquidity pool for a token pair.
     *         Permissionless -- anyone can create a pool.
     *
     * @param tokenA First token address (ETH_ADDRESS for native ETH)
     * @param tokenB Second token address (ETH_ADDRESS for native ETH)
     */
    function createPool(address tokenA, address tokenB) external returns (bytes32 poolId) {
        if (tokenA == address(0) || tokenB == address(0)) revert ZeroAddress();
        if (tokenA == tokenB) revert SameToken();

        (address token0, address token1) = _sortTokens(tokenA, tokenB);
        poolId = _getPoolId(token0, token1);

        if (pools[poolId].token0 != address(0)) revert PoolExists();

        pools[poolId] = Pool({
            token0: token0,
            token1: token1,
            reserve0: 0,
            reserve1: 0,
            totalLiquidity: 0,
            kLast: 0
        });

        emit PoolCreated(poolId, token0, token1);
    }

    // ---------------------------------------------------------------
    //  Add liquidity
    // ---------------------------------------------------------------

    /**
     * @notice Add liquidity to an ERC-20 / ERC-20 pool.
     *
     * @param tokenA       First token
     * @param tokenB       Second token
     * @param amountA      Amount of tokenA to deposit
     * @param amountB      Amount of tokenB to deposit
     * @param minLiquidity Minimum LP tokens to receive (slippage protection)
     */
    function addLiquidity(
        address tokenA,
        address tokenB,
        uint256 amountA,
        uint256 amountB,
        uint256 minLiquidity
    ) external nonReentrant returns (uint256 liquidity) {
        if (tokenA == ETH_ADDRESS || tokenB == ETH_ADDRESS) revert ZeroAddress();
        if (amountA == 0 || amountB == 0) revert ZeroAmount();

        (address token0, address token1) = _sortTokens(tokenA, tokenB);
        bytes32 poolId = _getPoolId(token0, token1);
        Pool storage pool = pools[poolId];
        if (pool.token0 == address(0)) revert PoolNotFound();

        // Determine actual deposit amounts (match ratio for existing pools)
        (uint256 amount0, uint256 amount1) = tokenA == token0
            ? (amountA, amountB)
            : (amountB, amountA);

        // Transfer tokens in
        _transferTokenIn(token0, msg.sender, amount0);
        _transferTokenIn(token1, msg.sender, amount1);

        liquidity = _mintLiquidity(poolId, pool, amount0, amount1);
        if (liquidity < minLiquidity) revert InsufficientLiquidity();

        emit LiquidityAdded(poolId, msg.sender, amount0, amount1, liquidity);
    }

    /**
     * @notice Add liquidity to an ETH / ERC-20 pool.
     *
     * @param token        The ERC-20 token (paired with ETH)
     * @param amountToken  Amount of the ERC-20 token to deposit
     * @param minLiquidity Minimum LP tokens to receive
     */
    function addLiquidityETH(
        address token,
        uint256 amountToken,
        uint256 minLiquidity
    ) external payable nonReentrant returns (uint256 liquidity) {
        if (token == address(0) || token == ETH_ADDRESS) revert ZeroAddress();
        if (msg.value == 0 || amountToken == 0) revert ZeroAmount();

        (address token0, address token1) = _sortTokens(ETH_ADDRESS, token);
        bytes32 poolId = _getPoolId(token0, token1);
        Pool storage pool = pools[poolId];
        if (pool.token0 == address(0)) revert PoolNotFound();

        uint256 amount0;
        uint256 amount1;
        if (token0 == ETH_ADDRESS) {
            amount0 = msg.value;
            amount1 = amountToken;
            _transferTokenIn(token1, msg.sender, amount1);
        } else {
            amount0 = amountToken;
            amount1 = msg.value;
            _transferTokenIn(token0, msg.sender, amount0);
        }

        liquidity = _mintLiquidity(poolId, pool, amount0, amount1);
        if (liquidity < minLiquidity) revert InsufficientLiquidity();

        emit LiquidityAdded(poolId, msg.sender, amount0, amount1, liquidity);
    }

    // ---------------------------------------------------------------
    //  Remove liquidity
    // ---------------------------------------------------------------

    /**
     * @notice Remove liquidity from an ERC-20 / ERC-20 pool.
     *
     * @param tokenA    First token
     * @param tokenB    Second token
     * @param liquidity Amount of LP tokens to burn
     * @param minA      Minimum amount of tokenA to receive
     * @param minB      Minimum amount of tokenB to receive
     */
    function removeLiquidity(
        address tokenA,
        address tokenB,
        uint256 liquidity,
        uint256 minA,
        uint256 minB
    ) external nonReentrant returns (uint256 amountA, uint256 amountB) {
        if (tokenA == ETH_ADDRESS || tokenB == ETH_ADDRESS) revert ZeroAddress();
        if (liquidity == 0) revert ZeroAmount();

        (address token0, address token1) = _sortTokens(tokenA, tokenB);
        bytes32 poolId = _getPoolId(token0, token1);
        Pool storage pool = pools[poolId];
        if (pool.token0 == address(0)) revert PoolNotFound();

        (uint256 amount0, uint256 amount1) = _burnLiquidity(poolId, pool, liquidity);

        // Map back to caller's token ordering
        if (tokenA == token0) {
            amountA = amount0;
            amountB = amount1;
        } else {
            amountA = amount1;
            amountB = amount0;
        }

        if (amountA < minA) revert InsufficientAAmount();
        if (amountB < minB) revert InsufficientBAmount();

        // Transfer tokens out
        _transferTokenOut(token0, msg.sender, amount0);
        _transferTokenOut(token1, msg.sender, amount1);

        emit LiquidityRemoved(poolId, msg.sender, amount0, amount1, liquidity);
    }

    /**
     * @notice Remove liquidity from an ETH / ERC-20 pool.
     *
     * @param token     The ERC-20 token (paired with ETH)
     * @param liquidity Amount of LP tokens to burn
     * @param minToken  Minimum ERC-20 tokens to receive
     * @param minETH    Minimum ETH to receive
     */
    function removeLiquidityETH(
        address token,
        uint256 liquidity,
        uint256 minToken,
        uint256 minETH
    ) external nonReentrant returns (uint256 amountToken, uint256 amountETH) {
        if (token == address(0) || token == ETH_ADDRESS) revert ZeroAddress();
        if (liquidity == 0) revert ZeroAmount();

        (address token0, address token1) = _sortTokens(ETH_ADDRESS, token);
        bytes32 poolId = _getPoolId(token0, token1);
        Pool storage pool = pools[poolId];
        if (pool.token0 == address(0)) revert PoolNotFound();

        (uint256 amount0, uint256 amount1) = _burnLiquidity(poolId, pool, liquidity);

        if (token0 == ETH_ADDRESS) {
            amountETH = amount0;
            amountToken = amount1;
        } else {
            amountToken = amount0;
            amountETH = amount1;
        }

        if (amountToken < minToken) revert InsufficientAAmount();
        if (amountETH < minETH) revert InsufficientBAmount();

        // Transfer ERC-20 out
        _transferTokenOut(token, msg.sender, amountToken);

        // Credit ETH via pull pattern
        ethBalances[msg.sender] += amountETH;

        emit LiquidityRemoved(poolId, msg.sender, amount0, amount1, liquidity);
    }

    // ---------------------------------------------------------------
    //  Swap
    // ---------------------------------------------------------------

    /**
     * @notice Swap ERC-20 for ERC-20 through a pool.
     *
     * @param tokenIn     Token being sold
     * @param tokenOut    Token being bought
     * @param amountIn    Amount of tokenIn to sell
     * @param minAmountOut Minimum output (slippage protection)
     */
    function swap(
        address tokenIn,
        address tokenOut,
        uint256 amountIn,
        uint256 minAmountOut
    ) external nonReentrant returns (uint256 amountOut) {
        if (tokenIn == ETH_ADDRESS || tokenOut == ETH_ADDRESS) revert ZeroAddress();
        if (amountIn == 0) revert ZeroAmount();
        if (tokenIn == tokenOut) revert SameToken();

        (address token0, address token1) = _sortTokens(tokenIn, tokenOut);
        bytes32 poolId = _getPoolId(token0, token1);
        Pool storage pool = pools[poolId];
        if (pool.token0 == address(0)) revert PoolNotFound();

        // Transfer input token
        _transferTokenIn(tokenIn, msg.sender, amountIn);

        amountOut = _executeSwap(pool, tokenIn, amountIn);
        if (amountOut < minAmountOut) revert InsufficientOutput();

        // Transfer output token
        _transferTokenOut(tokenOut, msg.sender, amountOut);

        emit Swap(poolId, msg.sender, tokenIn, tokenOut, amountIn, amountOut);
    }

    /**
     * @notice Swap native ETH for an ERC-20 token.
     *
     * @param token        The ERC-20 token to buy
     * @param minAmountOut Minimum token output
     */
    function swapETHForToken(
        address token,
        uint256 minAmountOut
    ) external payable nonReentrant returns (uint256 amountOut) {
        if (token == address(0) || token == ETH_ADDRESS) revert ZeroAddress();
        if (msg.value == 0) revert ZeroAmount();

        (address token0, address token1) = _sortTokens(ETH_ADDRESS, token);
        bytes32 poolId = _getPoolId(token0, token1);
        Pool storage pool = pools[poolId];
        if (pool.token0 == address(0)) revert PoolNotFound();

        amountOut = _executeSwap(pool, ETH_ADDRESS, msg.value);
        if (amountOut < minAmountOut) revert InsufficientOutput();

        // Transfer ERC-20 token out
        _transferTokenOut(token, msg.sender, amountOut);

        emit Swap(poolId, msg.sender, ETH_ADDRESS, token, msg.value, amountOut);
    }

    /**
     * @notice Swap an ERC-20 token for native ETH.
     *
     * @param token   The ERC-20 token to sell
     * @param amountIn Amount of token to sell
     * @param minETH  Minimum ETH output
     */
    function swapTokenForETH(
        address token,
        uint256 amountIn,
        uint256 minETH
    ) external nonReentrant returns (uint256 amountOut) {
        if (token == address(0) || token == ETH_ADDRESS) revert ZeroAddress();
        if (amountIn == 0) revert ZeroAmount();

        (address token0, address token1) = _sortTokens(ETH_ADDRESS, token);
        bytes32 poolId = _getPoolId(token0, token1);
        Pool storage pool = pools[poolId];
        if (pool.token0 == address(0)) revert PoolNotFound();

        // Transfer ERC-20 in
        _transferTokenIn(token, msg.sender, amountIn);

        amountOut = _executeSwap(pool, token, amountIn);
        if (amountOut < minETH) revert InsufficientOutput();

        // Credit ETH via pull pattern
        ethBalances[msg.sender] += amountOut;

        emit Swap(poolId, msg.sender, token, ETH_ADDRESS, amountIn, amountOut);
    }

    // ---------------------------------------------------------------
    //  ETH withdrawal (pull pattern)
    // ---------------------------------------------------------------

    /**
     * @notice Withdraw credited ETH (from swaps and liquidity removal).
     */
    function withdrawEth() external nonReentrant {
        uint256 balance = ethBalances[msg.sender];
        if (balance == 0) revert NothingToWithdraw();
        ethBalances[msg.sender] = 0;

        (bool sent,) = payable(msg.sender).call{value: balance}("");
        if (!sent) revert TransferFailed();

        emit EthWithdrawn(msg.sender, balance);
    }

    // ---------------------------------------------------------------
    //  View functions
    // ---------------------------------------------------------------

    /**
     * @notice Get pool data for a token pair.
     */
    function getPool(address tokenA, address tokenB) external view returns (Pool memory) {
        (address token0, address token1) = _sortTokens(tokenA, tokenB);
        bytes32 poolId = _getPoolId(token0, token1);
        return pools[poolId];
    }

    /**
     * @notice Get the pool ID for a token pair.
     */
    function getPoolId(address tokenA, address tokenB) external pure returns (bytes32) {
        (address token0, address token1) = _sortTokens(tokenA, tokenB);
        return _getPoolId(token0, token1);
    }

    /**
     * @notice Get LP balance for a user in a specific pool.
     */
    function getLiquidityBalance(
        address tokenA,
        address tokenB,
        address provider
    ) external view returns (uint256) {
        (address token0, address token1) = _sortTokens(tokenA, tokenB);
        bytes32 poolId = _getPoolId(token0, token1);
        return liquidityBalances[poolId][provider];
    }

    /**
     * @notice Calculate output amount for a given input using constant product formula.
     *         Includes 0.3% fee on input.
     *
     * @param amountIn   Amount of input token
     * @param reserveIn  Reserve of input token
     * @param reserveOut Reserve of output token
     * @return amountOut Expected output amount
     */
    function getAmountOut(
        uint256 amountIn,
        uint256 reserveIn,
        uint256 reserveOut
    ) public pure returns (uint256 amountOut) {
        if (amountIn == 0) revert ZeroAmount();
        if (reserveIn == 0 || reserveOut == 0) revert InsufficientLiquidity();

        uint256 amountInWithFee = amountIn * (FEE_DENOMINATOR - FEE_NUMERATOR);
        uint256 numerator = amountInWithFee * reserveOut;
        uint256 denominator = (reserveIn * FEE_DENOMINATOR) + amountInWithFee;
        amountOut = numerator / denominator;
    }

    /**
     * @notice Get expected output for a swap (convenience view).
     *
     * @param tokenIn  Input token address
     * @param tokenOut Output token address
     * @param amountIn Amount of input token
     * @return amountOut Expected output amount
     */
    function quote(
        address tokenIn,
        address tokenOut,
        uint256 amountIn
    ) external view returns (uint256 amountOut) {
        (address token0, address token1) = _sortTokens(tokenIn, tokenOut);
        bytes32 poolId = _getPoolId(token0, token1);
        Pool storage pool = pools[poolId];
        if (pool.token0 == address(0)) revert PoolNotFound();

        uint256 reserveIn;
        uint256 reserveOut;
        if (tokenIn == token0) {
            reserveIn = pool.reserve0;
            reserveOut = pool.reserve1;
        } else {
            reserveIn = pool.reserve1;
            reserveOut = pool.reserve0;
        }

        amountOut = getAmountOut(amountIn, reserveIn, reserveOut);
    }

    // ---------------------------------------------------------------
    //  Internal: Liquidity math
    // ---------------------------------------------------------------

    function _mintLiquidity(
        bytes32 poolId,
        Pool storage pool,
        uint256 amount0,
        uint256 amount1
    ) private returns (uint256 liquidity) {
        if (pool.totalLiquidity == 0) {
            // First deposit: LP = sqrt(amount0 * amount1) - MINIMUM_LIQUIDITY
            liquidity = _sqrt(amount0 * amount1);
            if (liquidity <= MINIMUM_LIQUIDITY) revert InsufficientLiquidity();
            liquidity -= MINIMUM_LIQUIDITY;
            // Burn minimum liquidity to the zero address
            liquidityBalances[poolId][address(0)] += MINIMUM_LIQUIDITY;
            pool.totalLiquidity = MINIMUM_LIQUIDITY;
        } else {
            // Subsequent deposits: proportional to existing reserves
            uint256 liquidity0 = (amount0 * pool.totalLiquidity) / pool.reserve0;
            uint256 liquidity1 = (amount1 * pool.totalLiquidity) / pool.reserve1;
            liquidity = liquidity0 < liquidity1 ? liquidity0 : liquidity1;
        }

        if (liquidity == 0) revert InsufficientLiquidity();

        liquidityBalances[poolId][msg.sender] += liquidity;
        pool.totalLiquidity += liquidity;
        pool.reserve0 += amount0;
        pool.reserve1 += amount1;
        pool.kLast = pool.reserve0 * pool.reserve1;
    }

    function _burnLiquidity(
        bytes32 poolId,
        Pool storage pool,
        uint256 liquidity
    ) private returns (uint256 amount0, uint256 amount1) {
        if (liquidityBalances[poolId][msg.sender] < liquidity) revert InsufficientLiquidity();

        amount0 = (liquidity * pool.reserve0) / pool.totalLiquidity;
        amount1 = (liquidity * pool.reserve1) / pool.totalLiquidity;
        if (amount0 == 0 || amount1 == 0) revert InsufficientLiquidity();

        liquidityBalances[poolId][msg.sender] -= liquidity;
        pool.totalLiquidity -= liquidity;
        pool.reserve0 -= amount0;
        pool.reserve1 -= amount1;
        pool.kLast = pool.reserve0 * pool.reserve1;
    }

    // ---------------------------------------------------------------
    //  Internal: Swap logic
    // ---------------------------------------------------------------

    function _executeSwap(
        Pool storage pool,
        address tokenIn,
        uint256 amountIn
    ) private returns (uint256 amountOut) {
        uint256 reserveIn;
        uint256 reserveOut;

        if (tokenIn == pool.token0) {
            reserveIn = pool.reserve0;
            reserveOut = pool.reserve1;
        } else {
            reserveIn = pool.reserve1;
            reserveOut = pool.reserve0;
        }

        amountOut = getAmountOut(amountIn, reserveIn, reserveOut);
        if (amountOut == 0) revert InsufficientOutput();

        // Update reserves
        if (tokenIn == pool.token0) {
            pool.reserve0 += amountIn;
            pool.reserve1 -= amountOut;
        } else {
            pool.reserve1 += amountIn;
            pool.reserve0 -= amountOut;
        }

        pool.kLast = pool.reserve0 * pool.reserve1;
    }

    // ---------------------------------------------------------------
    //  Internal: Token transfers
    // ---------------------------------------------------------------

    function _transferTokenIn(address token, address from, uint256 amount) private {
        if (token == ETH_ADDRESS) {
            // ETH already received via msg.value -- no-op
            return;
        }
        bool ok = IERC20(token).transferFrom(from, address(this), amount);
        if (!ok) revert TransferFailed();
    }

    function _transferTokenOut(address token, address to, uint256 amount) private {
        if (token == ETH_ADDRESS) {
            (bool sent,) = payable(to).call{value: amount}("");
            if (!sent) revert TransferFailed();
            return;
        }
        bool ok = IERC20(token).transfer(to, amount);
        if (!ok) revert TransferFailed();
    }

    // ---------------------------------------------------------------
    //  Internal: Helpers
    // ---------------------------------------------------------------

    /// @notice Sort two token addresses for deterministic pool IDs.
    function _sortTokens(address a, address b) private pure returns (address, address) {
        return a < b ? (a, b) : (b, a);
    }

    /// @notice Compute deterministic pool ID from sorted token pair.
    function _getPoolId(address token0, address token1) private pure returns (bytes32) {
        return keccak256(abi.encodePacked(token0, token1));
    }

    /// @notice Babylonian method integer square root.
    function _sqrt(uint256 y) private pure returns (uint256 z) {
        if (y > 3) {
            z = y;
            uint256 x = y / 2 + 1;
            while (x < z) {
                z = x;
                x = (y / x + x) / 2;
            }
        } else if (y != 0) {
            z = 1;
        }
    }

    // ---------------------------------------------------------------
    //  Receive ETH
    // ---------------------------------------------------------------

    receive() external payable {}
}

contracts/orbital/OrbitalFactory.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./OrbitalPool.sol";

/**
 * @title OrbitalFactory
 * @notice Factory contract for deploying OrbitalPool instances.
 *
 *         Maintains a registry of all pools, indexed by a deterministic
 *         pool key derived from the sorted token set. Ensures only one
 *         pool exists per unique combination of tokens + concentration.
 *
 * @dev    Follows existing Fueki platform conventions.
 */
contract OrbitalFactory {

    // ---------------------------------------------------------------
    //  Storage
    // ---------------------------------------------------------------

    /// @notice Admin address (can update default parameters).
    address public admin;

    /// @notice Default fee collector for new pools.
    address public defaultFeeCollector;

    /// @notice Default swap fee in basis points for new pools.
    uint256 public defaultSwapFeeBps;

    /// @notice Ordered list of all pools ever created.
    address[] private _allPools;

    /// @notice poolKey => pool address. poolKey = keccak256(sorted tokens + concentration).
    mapping(bytes32 => address) public poolsByKey;

    /// @notice token => list of pools that include this token.
    mapping(address => address[]) private _tokenPools;

    // ---------------------------------------------------------------
    //  Events
    // ---------------------------------------------------------------

    event PoolCreated(
        address indexed pool,
        address[] tokens,
        uint8 concentration,
        uint256 swapFeeBps,
        address feeCollector
    );

    event AdminUpdated(address indexed oldAdmin, address indexed newAdmin);
    event DefaultFeeCollectorUpdated(address indexed collector);
    event DefaultSwapFeeUpdated(uint256 newFeeBps);

    // ---------------------------------------------------------------
    //  Errors
    // ---------------------------------------------------------------

    error NotAdmin();
    error ZeroAddress();
    error PoolExists();
    error InvalidFee();

    // ---------------------------------------------------------------
    //  Modifiers
    // ---------------------------------------------------------------

    modifier onlyAdmin() {
        if (msg.sender != admin) revert NotAdmin();
        _;
    }

    // ---------------------------------------------------------------
    //  Constructor
    // ---------------------------------------------------------------

    /**
     * @param _admin             Initial admin address.
     * @param _feeCollector      Default fee collector for new pools.
     * @param _defaultSwapFeeBps Default swap fee in bps (e.g., 4 = 0.04%).
     */
    constructor(
        address _admin,
        address _feeCollector,
        uint256 _defaultSwapFeeBps
    ) {
        if (_admin == address(0) || _feeCollector == address(0)) revert ZeroAddress();
        if (_defaultSwapFeeBps > 100) revert InvalidFee();

        admin = _admin;
        defaultFeeCollector = _feeCollector;
        defaultSwapFeeBps = _defaultSwapFeeBps;
    }

    // ---------------------------------------------------------------
    //  Pool Creation
    // ---------------------------------------------------------------

    /**
     * @notice Create a new OrbitalPool for a given set of tokens.
     *
     * @param _tokens         Array of token addresses (2-8 tokens).
     * @param _concentration  Superellipse power (2, 4, 8, 16, 32).
     * @param _swapFeeBps     Swap fee in basis points (0 = use default).
     * @param _name           LP token name.
     * @param _symbol         LP token symbol.
     * @return pool           Address of the newly created pool.
     */
    function createPool(
        address[] calldata _tokens,
        uint8 _concentration,
        uint256 _swapFeeBps,
        string calldata _name,
        string calldata _symbol
    ) external returns (address pool) {
        // Use default fee if not specified
        uint256 feeBps = _swapFeeBps == 0 ? defaultSwapFeeBps : _swapFeeBps;

        // Compute pool key for uniqueness check
        bytes32 poolKey = _computePoolKey(_tokens, _concentration);
        if (poolsByKey[poolKey] != address(0)) revert PoolExists();

        // Deploy new pool
        OrbitalPool newPool = new OrbitalPool();
        pool = address(newPool);

        // Initialize the pool
        newPool.initialize(
            _tokens,
            _concentration,
            feeBps,
            defaultFeeCollector,
            _name,
            _symbol
        );

        // Register in storage
        poolsByKey[poolKey] = pool;
        _allPools.push(pool);

        // Index by token for lookup
        for (uint256 i = 0; i < _tokens.length; ++i) {
            _tokenPools[_tokens[i]].push(pool);
        }

        emit PoolCreated(pool, _tokens, _concentration, feeBps, defaultFeeCollector);
    }

    // ---------------------------------------------------------------
    //  View Functions
    // ---------------------------------------------------------------

    /// @notice Get total number of pools created.
    function totalPools() external view returns (uint256) {
        return _allPools.length;
    }

    /// @notice Get pool address at a given index.
    function getPoolAtIndex(uint256 index) external view returns (address) {
        return _allPools[index];
    }

    /// @notice Get all pool addresses.
    function getAllPools() external view returns (address[] memory) {
        return _allPools;
    }

    /// @notice Get pool address for a specific token set + concentration.
    function getPool(
        address[] calldata _tokens,
        uint8 _concentration
    ) external view returns (address) {
        bytes32 poolKey = _computePoolKey(_tokens, _concentration);
        return poolsByKey[poolKey];
    }

    /// @notice Get all pools that include a specific token.
    function getPoolsForToken(address token) external view returns (address[] memory) {
        return _tokenPools[token];
    }

    // ---------------------------------------------------------------
    //  Admin Functions
    // ---------------------------------------------------------------

    function setAdmin(address _newAdmin) external onlyAdmin {
        if (_newAdmin == address(0)) revert ZeroAddress();
        address old = admin;
        admin = _newAdmin;
        emit AdminUpdated(old, _newAdmin);
    }

    function setDefaultFeeCollector(address _collector) external onlyAdmin {
        if (_collector == address(0)) revert ZeroAddress();
        defaultFeeCollector = _collector;
        emit DefaultFeeCollectorUpdated(_collector);
    }

    function setDefaultSwapFee(uint256 _feeBps) external onlyAdmin {
        if (_feeBps > 100) revert InvalidFee();
        defaultSwapFeeBps = _feeBps;
        emit DefaultSwapFeeUpdated(_feeBps);
    }

    // ---------------------------------------------------------------
    //  Internal
    // ---------------------------------------------------------------

    /**
     * @notice Compute a deterministic pool key from sorted tokens + concentration.
     *         Tokens are sorted to ensure the same set always produces the same key.
     */
    function _computePoolKey(
        address[] calldata _tokens,
        uint8 _concentration
    ) internal pure returns (bytes32) {
        // Sort tokens for deterministic key
        address[] memory sorted = new address[](_tokens.length);
        for (uint256 i = 0; i < _tokens.length; ++i) {
            sorted[i] = _tokens[i];
        }
        _sortAddresses(sorted);

        return keccak256(abi.encodePacked(sorted, _concentration));
    }

    /// @notice Sort an array of addresses in ascending order (insertion sort).
    function _sortAddresses(address[] memory arr) internal pure {
        uint256 n = arr.length;
        for (uint256 i = 1; i < n; ++i) {
            address key = arr[i];
            uint256 j = i;
            while (j > 0 && arr[j - 1] > key) {
                arr[j] = arr[j - 1];
                --j;
            }
            arr[j] = key;
        }
    }
}

contracts/orbital/OrbitalMath.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title OrbitalMath
 * @notice Fixed-point math library for the Orbital AMM superellipse invariant.
 *
 *         The Orbital AMM uses a superellipse curve: Sum(xi^p) = K
 *         where xi are WAD-normalized reserves, p is the concentration
 *         parameter, and K is the invariant constant.
 *
 *         All values use WAD (1e18) fixed-point representation.
 *         Supported concentration powers: 2, 4, 8, 16, 32.
 *         These are computed via repeated squaring / repeated sqrt.
 *
 * @dev    Designed for gas efficiency -- no loops for power computation,
 *         only chained multiplications and square roots.
 */
library OrbitalMath {

    // ---------------------------------------------------------------
    //  Constants
    // ---------------------------------------------------------------

    uint256 internal constant WAD = 1e18;
    uint256 internal constant HALF_WAD = 5e17;

    // ---------------------------------------------------------------
    //  Errors
    // ---------------------------------------------------------------

    error MathOverflow();
    error InvalidPower();
    error ZeroInput();
    error InvariantViolation();

    // ---------------------------------------------------------------
    //  WAD Arithmetic
    // ---------------------------------------------------------------

    /// @notice WAD multiply: (a * b) / WAD, rounded down.
    function wadMul(uint256 a, uint256 b) internal pure returns (uint256) {
        return (a * b) / WAD;
    }

    /// @notice WAD multiply with rounding to nearest: (a * b + HALF_WAD) / WAD.
    function wadMulRound(uint256 a, uint256 b) internal pure returns (uint256) {
        return (a * b + HALF_WAD) / WAD;
    }

    /// @notice WAD divide: (a * WAD) / b, rounded down.
    function wadDiv(uint256 a, uint256 b) internal pure returns (uint256) {
        if (b == 0) revert ZeroInput();
        return (a * WAD) / b;
    }

    // ---------------------------------------------------------------
    //  Power Functions (WAD-scaled)
    // ---------------------------------------------------------------

    /// @notice Compute x^2 in WAD arithmetic.
    function wadPow2(uint256 x) internal pure returns (uint256) {
        return (x * x) / WAD;
    }

    /// @notice Compute x^4 in WAD arithmetic.
    function wadPow4(uint256 x) internal pure returns (uint256) {
        uint256 x2 = (x * x) / WAD;
        return (x2 * x2) / WAD;
    }

    /// @notice Compute x^8 in WAD arithmetic.
    function wadPow8(uint256 x) internal pure returns (uint256) {
        uint256 x2 = (x * x) / WAD;
        uint256 x4 = (x2 * x2) / WAD;
        return (x4 * x4) / WAD;
    }

    /// @notice Compute x^16 in WAD arithmetic.
    function wadPow16(uint256 x) internal pure returns (uint256) {
        uint256 x2 = (x * x) / WAD;
        uint256 x4 = (x2 * x2) / WAD;
        uint256 x8 = (x4 * x4) / WAD;
        return (x8 * x8) / WAD;
    }

    /// @notice Compute x^32 in WAD arithmetic.
    function wadPow32(uint256 x) internal pure returns (uint256) {
        uint256 x2 = (x * x) / WAD;
        uint256 x4 = (x2 * x2) / WAD;
        uint256 x8 = (x4 * x4) / WAD;
        uint256 x16 = (x8 * x8) / WAD;
        return (x16 * x16) / WAD;
    }

    /// @notice Compute x^p in WAD arithmetic for supported powers.
    /// @param x    WAD-scaled input value.
    /// @param p    Power exponent (must be 2, 4, 8, 16, or 32).
    /// @return result WAD-scaled x^p.
    function wadPow(uint256 x, uint8 p) internal pure returns (uint256 result) {
        if (p == 2) return wadPow2(x);
        if (p == 4) return wadPow4(x);
        if (p == 8) return wadPow8(x);
        if (p == 16) return wadPow16(x);
        if (p == 32) return wadPow32(x);
        revert InvalidPower();
    }

    // ---------------------------------------------------------------
    //  Root Functions (WAD-scaled)
    // ---------------------------------------------------------------

    /// @notice Compute the integer square root of y using the Babylonian method.
    ///         NOT WAD-scaled -- operates on raw integers.
    function sqrt(uint256 y) internal pure returns (uint256 z) {
        if (y > 3) {
            z = y;
            uint256 x = y / 2 + 1;
            while (x < z) {
                z = x;
                x = (y / x + x) / 2;
            }
        } else if (y != 0) {
            z = 1;
        }
    }

    /// @notice Compute the square root of a WAD-scaled value, returning WAD-scaled result.
    ///         wadSqrt(x) = sqrt(x * WAD) so that wadSqrt(4e18) = 2e18.
    function wadSqrt(uint256 x) internal pure returns (uint256) {
        if (x == 0) return 0;
        return sqrt(x * WAD);
    }

    /// @notice Compute x^(1/2) in WAD.
    function wadRoot2(uint256 x) internal pure returns (uint256) {
        return wadSqrt(x);
    }

    /// @notice Compute x^(1/4) in WAD = sqrt(sqrt(x)).
    function wadRoot4(uint256 x) internal pure returns (uint256) {
        return wadSqrt(wadSqrt(x));
    }

    /// @notice Compute x^(1/8) in WAD = sqrt(sqrt(sqrt(x))).
    function wadRoot8(uint256 x) internal pure returns (uint256) {
        return wadSqrt(wadSqrt(wadSqrt(x)));
    }

    /// @notice Compute x^(1/16) in WAD.
    function wadRoot16(uint256 x) internal pure returns (uint256) {
        return wadSqrt(wadSqrt(wadSqrt(wadSqrt(x))));
    }

    /// @notice Compute x^(1/32) in WAD.
    function wadRoot32(uint256 x) internal pure returns (uint256) {
        return wadSqrt(wadSqrt(wadSqrt(wadSqrt(wadSqrt(x)))));
    }

    /// @notice Compute x^(1/p) in WAD arithmetic for supported powers.
    /// @param x    WAD-scaled input value.
    /// @param p    Root index (must be 2, 4, 8, 16, or 32).
    /// @return result WAD-scaled x^(1/p).
    function wadRoot(uint256 x, uint8 p) internal pure returns (uint256 result) {
        if (p == 2) return wadRoot2(x);
        if (p == 4) return wadRoot4(x);
        if (p == 8) return wadRoot8(x);
        if (p == 16) return wadRoot16(x);
        if (p == 32) return wadRoot32(x);
        revert InvalidPower();
    }

    // ---------------------------------------------------------------
    //  Orbital AMM Core Computations
    // ---------------------------------------------------------------

    /**
     * @notice Compute the superellipse invariant K = Sum(xi^p) for given
     *         WAD-normalized reserves.
     *
     * @param normalizedReserves  Array of WAD-normalized reserve values.
     *                            At equilibrium, each value equals WAD (1e18).
     * @param p                   Concentration power (2, 4, 8, 16, 32).
     * @return K  The invariant constant (WAD-scaled).
     */
    function computeInvariant(
        uint256[] memory normalizedReserves,
        uint8 p
    ) internal pure returns (uint256 K) {
        uint256 n = normalizedReserves.length;
        for (uint256 i = 0; i < n; ++i) {
            K += wadPow(normalizedReserves[i], p);
        }
    }

    /**
     * @notice Compute the output amount for a swap using the superellipse invariant.
     *
     *         Given:
     *           - Current normalized reserves: x[0], x[1], ..., x[n-1]
     *           - Input token index: tokenIn
     *           - Output token index: tokenOut
     *           - Normalized input amount (after fees): dxNorm
     *           - Concentration power: p
     *
     *         The invariant K = Sum(xi^p) must be preserved.
     *         New x[tokenIn] = old x[tokenIn] + dxNorm
     *         New x[tokenOut] = (K - Sum_{k != tokenOut} x[k]_new^p) ^ (1/p)
     *         Output = old x[tokenOut] - new x[tokenOut]
     *
     * @param normalizedReserves WAD-normalized reserves array.
     * @param tokenInIndex       Index of input token.
     * @param tokenOutIndex      Index of output token.
     * @param dxNorm             WAD-normalized input amount (after fee).
     * @param p                  Concentration power.
     * @return dyNorm WAD-normalized output amount.
     */
    function computeSwapOutput(
        uint256[] memory normalizedReserves,
        uint256 tokenInIndex,
        uint256 tokenOutIndex,
        uint256 dxNorm,
        uint8 p
    ) internal pure returns (uint256 dyNorm) {
        uint256 n = normalizedReserves.length;

        // Compute K (current invariant)
        uint256 K = computeInvariant(normalizedReserves, p);

        // Compute sum of x[k]^p for k != tokenOut, with updated x[tokenIn]
        uint256 sumOthers = 0;
        for (uint256 k = 0; k < n; ++k) {
            if (k == tokenOutIndex) continue;
            uint256 xk = normalizedReserves[k];
            if (k == tokenInIndex) {
                xk += dxNorm;
            }
            sumOthers += wadPow(xk, p);
        }

        // The new reserve for tokenOut must satisfy: sumOthers + x[tokenOut]_new^p = K
        if (sumOthers >= K) revert InvariantViolation();
        uint256 remainder = K - sumOthers;

        // x[tokenOut]_new = remainder^(1/p)
        uint256 newReserveOut = wadRoot(remainder, p);

        // Output is the decrease in tokenOut reserve
        uint256 oldReserveOut = normalizedReserves[tokenOutIndex];
        if (newReserveOut >= oldReserveOut) revert InvariantViolation();

        dyNorm = oldReserveOut - newReserveOut;
    }

    /**
     * @notice Compute the amount of LP tokens to mint for a balanced deposit.
     *
     *         For a balanced deposit where each token amount is proportional
     *         to current reserves, LP tokens are minted proportional to the
     *         increase in the invariant K.
     *
     * @param currentK       Current invariant K.
     * @param newK           New invariant K after deposit.
     * @param totalLiquidity Current total LP supply.
     * @param p              Concentration power.
     * @return mintAmount    Number of LP tokens to mint.
     */
    function computeLiquidityMint(
        uint256 currentK,
        uint256 newK,
        uint256 totalLiquidity,
        uint8 p
    ) internal pure returns (uint256 mintAmount) {
        if (totalLiquidity == 0) {
            // First deposit: LP = K^(1/p) (geometric interpretation: "radius")
            mintAmount = wadRoot(newK, p);
        } else {
            // Subsequent deposits: proportional to K increase
            // LP_new = LP_old * (K_new^(1/p) / K_old^(1/p))
            uint256 oldRadius = wadRoot(currentK, p);
            uint256 newRadius = wadRoot(newK, p);
            if (newRadius <= oldRadius) revert InvariantViolation();
            mintAmount = (totalLiquidity * (newRadius - oldRadius)) / oldRadius;
        }
    }

    /**
     * @notice Compute the token amounts returned when burning LP tokens.
     *
     * @param reserves       Current raw reserves array.
     * @param liquidity      Amount of LP tokens to burn.
     * @param totalLiquidity Current total LP supply.
     * @return amounts       Array of token amounts to return.
     */
    function computeLiquidityBurn(
        uint256[] memory reserves,
        uint256 liquidity,
        uint256 totalLiquidity
    ) internal pure returns (uint256[] memory amounts) {
        uint256 n = reserves.length;
        amounts = new uint256[](n);
        for (uint256 i = 0; i < n; ++i) {
            amounts[i] = (reserves[i] * liquidity) / totalLiquidity;
        }
    }

    /**
     * @notice Normalize raw reserves to WAD scale relative to a reference
     *         total D. At equilibrium (all reserves equal), each normalized
     *         value equals WAD.
     *
     * @param reserves Raw reserve amounts.
     * @param n        Number of tokens.
     * @return normalized Array of WAD-normalized reserves.
     * @return D        Sum of all reserves (used as normalization base).
     */
    function normalizeReserves(
        uint256[] memory reserves,
        uint256 n
    ) internal pure returns (uint256[] memory normalized, uint256 D) {
        normalized = new uint256[](n);
        for (uint256 i = 0; i < n; ++i) {
            D += reserves[i];
        }
        if (D == 0) revert ZeroInput();
        for (uint256 i = 0; i < n; ++i) {
            // xi = n * ri * WAD / D
            // At equilibrium: ri = D/n, so xi = n * (D/n) * WAD / D = WAD
            normalized[i] = (n * reserves[i] * WAD) / D;
        }
    }
}

contracts/orbital/OrbitalPool.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./OrbitalMath.sol";

/**
 * @title OrbitalPool
 * @notice Core AMM pool implementing the Orbital superellipse invariant.
 *
 *         The pool supports 2-8 ERC-20 tokens and uses the invariant:
 *           Sum(xi^p) = K
 *         where xi are WAD-normalized reserves and p is the concentration
 *         parameter. Higher p concentrates liquidity closer to 1:1 pricing.
 *
 *         Features:
 *         - N-token pools (2-8 tokens)
 *         - Configurable concentration power (2, 4, 8, 16, 32)
 *         - Configurable swap fee (in basis points)
 *         - ERC-20 LP token for liquidity positions
 *         - Proportional add/remove liquidity
 *         - Single-sided swap execution
 *
 * @dev    Follows existing Fueki platform conventions: no OpenZeppelin imports,
 *         manual reentrancy guard, custom errors, inline ERC-20 implementation
 *         for LP tokens.
 */

interface IERC20 {
    function totalSupply() external view returns (uint256);
    function balanceOf(address account) external view returns (uint256);
    function transfer(address to, uint256 amount) external returns (bool);
    function allowance(address owner, address spender) external view returns (uint256);
    function approve(address spender, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function decimals() external view returns (uint8);
}

contract OrbitalPool {
    using OrbitalMath for uint256;

    // ---------------------------------------------------------------
    //  Constants
    // ---------------------------------------------------------------

    uint256 public constant WAD = 1e18;
    uint256 public constant MINIMUM_LIQUIDITY = 1000;
    uint256 public constant MAX_TOKENS = 8;
    uint256 public constant MIN_TOKENS = 2;
    uint256 public constant MAX_FEE_BPS = 100; // 1% max fee
    uint256 public constant FEE_DENOMINATOR = 10000;

    // ---------------------------------------------------------------
    //  Pool Configuration (set once at initialization)
    // ---------------------------------------------------------------

    /// @notice Factory that created this pool.
    address public immutable factory;

    /// @notice Ordered array of token addresses in the pool.
    address[] public tokens;

    /// @notice Number of tokens in the pool.
    uint256 public numTokens;

    /// @notice Concentration power (2, 4, 8, 16, 32).
    ///         Higher = more concentrated around equal prices.
    uint8 public concentration;

    /// @notice Swap fee in basis points (e.g., 4 = 0.04%).
    uint256 public swapFeeBps;

    /// @notice Fee collector address (receives accumulated protocol fees).
    address public feeCollector;

    // ---------------------------------------------------------------
    //  Pool State
    // ---------------------------------------------------------------

    /// @notice Current reserve for each token (raw amounts in token decimals).
    uint256[] public reserves;

    /// @notice Whether the pool has been initialized with first liquidity.
    bool public initialized;

    // ---------------------------------------------------------------
    //  LP Token State (ERC-20 inline)
    // ---------------------------------------------------------------

    string public name;
    string public symbol;
    uint8 public constant lpDecimals = 18;
    uint256 public totalSupply;

    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;

    // ---------------------------------------------------------------
    //  Reentrancy Guard
    // ---------------------------------------------------------------

    uint256 private constant _NOT_ENTERED = 1;
    uint256 private constant _ENTERED = 2;
    uint256 private _status = _NOT_ENTERED;

    // ---------------------------------------------------------------
    //  Accumulated Fees
    // ---------------------------------------------------------------

    /// @notice Accumulated fees per token (not yet collected).
    uint256[] public accumulatedFees;

    // ---------------------------------------------------------------
    //  Events
    // ---------------------------------------------------------------

    event Swap(
        address indexed sender,
        uint256 tokenInIndex,
        uint256 tokenOutIndex,
        uint256 amountIn,
        uint256 amountOut,
        uint256 feeAmount
    );

    event LiquidityAdded(
        address indexed provider,
        uint256[] amounts,
        uint256 lpMinted
    );

    event LiquidityRemoved(
        address indexed provider,
        uint256[] amounts,
        uint256 lpBurned
    );

    event FeesCollected(
        address indexed collector,
        uint256[] amounts
    );

    // LP token events
    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);

    // ---------------------------------------------------------------
    //  Errors
    // ---------------------------------------------------------------

    error NotFactory();
    error AlreadyInitialized();
    error NotInitialized();
    error InvalidTokenCount();
    error InvalidConcentration();
    error InvalidFee();
    error ZeroAmount();
    error ZeroAddress();
    error DuplicateToken();
    error SameToken();
    error InvalidTokenIndex();
    error SlippageExceeded();
    error InsufficientLiquidity();
    error InsufficientBalance();
    error InsufficientAllowance();
    error TransferFailed();
    error ReentrantCall();
    error DeadlineExpired();
    error InvariantViolated();

    // ---------------------------------------------------------------
    //  Modifiers
    // ---------------------------------------------------------------

    modifier nonReentrant() {
        if (_status == _ENTERED) revert ReentrantCall();
        _status = _ENTERED;
        _;
        _status = _NOT_ENTERED;
    }

    modifier onlyFactory() {
        if (msg.sender != factory) revert NotFactory();
        _;
    }

    modifier whenInitialized() {
        if (!initialized) revert NotInitialized();
        _;
    }

    modifier checkDeadline(uint256 deadline) {
        if (block.timestamp > deadline) revert DeadlineExpired();
        _;
    }

    // ---------------------------------------------------------------
    //  Constructor
    // ---------------------------------------------------------------

    constructor() {
        factory = msg.sender;
    }

    // ---------------------------------------------------------------
    //  Initialization (called by factory)
    // ---------------------------------------------------------------

    /**
     * @notice Initialize the pool with token list and parameters.
     *         Called once by the factory immediately after deployment.
     *
     * @param _tokens         Ordered array of token addresses.
     * @param _concentration  Superellipse power (2, 4, 8, 16, 32).
     * @param _swapFeeBps     Swap fee in basis points.
     * @param _feeCollector   Address that receives protocol fees.
     * @param _name           LP token name.
     * @param _symbol         LP token symbol.
     */
    function initialize(
        address[] calldata _tokens,
        uint8 _concentration,
        uint256 _swapFeeBps,
        address _feeCollector,
        string calldata _name,
        string calldata _symbol
    ) external onlyFactory {
        if (initialized) revert AlreadyInitialized();
        if (_tokens.length < MIN_TOKENS || _tokens.length > MAX_TOKENS) revert InvalidTokenCount();
        if (_concentration != 2 && _concentration != 4 && _concentration != 8 &&
            _concentration != 16 && _concentration != 32) revert InvalidConcentration();
        if (_swapFeeBps > MAX_FEE_BPS) revert InvalidFee();
        if (_feeCollector == address(0)) revert ZeroAddress();

        // Validate tokens: no zero address, no duplicates
        for (uint256 i = 0; i < _tokens.length; ++i) {
            if (_tokens[i] == address(0)) revert ZeroAddress();
            for (uint256 j = 0; j < i; ++j) {
                if (_tokens[i] == _tokens[j]) revert DuplicateToken();
            }
        }

        numTokens = _tokens.length;
        concentration = _concentration;
        swapFeeBps = _swapFeeBps;
        feeCollector = _feeCollector;
        name = _name;
        symbol = _symbol;

        // Initialize storage arrays
        for (uint256 i = 0; i < _tokens.length; ++i) {
            tokens.push(_tokens[i]);
            reserves.push(0);
            accumulatedFees.push(0);
        }

        initialized = true;
    }

    // ---------------------------------------------------------------
    //  Swap
    // ---------------------------------------------------------------

    /**
     * @notice Swap tokenIn for tokenOut through the pool.
     *
     * @param tokenInIndex   Index of input token in the pool's token array.
     * @param tokenOutIndex  Index of output token in the pool's token array.
     * @param amountIn       Amount of input token to swap.
     * @param minAmountOut   Minimum output amount (slippage protection).
     * @param deadline       Transaction deadline (block.timestamp).
     * @return amountOut     Actual output amount.
     */
    function swap(
        uint256 tokenInIndex,
        uint256 tokenOutIndex,
        uint256 amountIn,
        uint256 minAmountOut,
        uint256 deadline
    ) external nonReentrant whenInitialized checkDeadline(deadline) returns (uint256 amountOut) {
        if (tokenInIndex >= numTokens) revert InvalidTokenIndex();
        if (tokenOutIndex >= numTokens) revert InvalidTokenIndex();
        if (tokenInIndex == tokenOutIndex) revert SameToken();
        if (amountIn == 0) revert ZeroAmount();

        // Apply swap fee
        uint256 feeAmount = (amountIn * swapFeeBps) / FEE_DENOMINATOR;
        uint256 amountInAfterFee = amountIn - feeAmount;

        // Compute normalized reserves
        uint256 n = numTokens;
        (uint256[] memory normalized, uint256 D) =
            OrbitalMath.normalizeReserves(reserves, n);

        // Normalize the input amount
        uint256 dxNorm = (n * amountInAfterFee * WAD) / D;

        // Compute output in normalized terms
        uint256 dyNorm = OrbitalMath.computeSwapOutput(
            normalized,
            tokenInIndex,
            tokenOutIndex,
            dxNorm,
            concentration
        );

        // Convert back to raw token amount
        amountOut = (dyNorm * D) / (n * WAD);

        // Slippage check
        if (amountOut < minAmountOut) revert SlippageExceeded();
        if (amountOut > reserves[tokenOutIndex]) revert InsufficientLiquidity();

        // Transfer input tokens from caller to pool
        _safeTransferFrom(tokens[tokenInIndex], msg.sender, address(this), amountIn);

        // Update reserves
        reserves[tokenInIndex] += amountInAfterFee;
        reserves[tokenOutIndex] -= amountOut;

        // Accumulate fees
        accumulatedFees[tokenInIndex] += feeAmount;

        // Transfer output tokens to caller
        _safeTransfer(tokens[tokenOutIndex], msg.sender, amountOut);

        emit Swap(msg.sender, tokenInIndex, tokenOutIndex, amountIn, amountOut, feeAmount);
    }

    // ---------------------------------------------------------------
    //  Add Liquidity
    // ---------------------------------------------------------------

    /**
     * @notice Add liquidity to the pool. For the first deposit, any ratio
     *         is accepted. Subsequent deposits must be proportional to
     *         current reserves.
     *
     * @param amounts       Array of token amounts to deposit (one per token).
     * @param minLiquidity  Minimum LP tokens to receive.
     * @param deadline      Transaction deadline.
     * @return liquidity    LP tokens minted.
     */
    function addLiquidity(
        uint256[] calldata amounts,
        uint256 minLiquidity,
        uint256 deadline
    ) external nonReentrant whenInitialized checkDeadline(deadline) returns (uint256 liquidity) {
        uint256 n = numTokens;
        if (amounts.length != n) revert InvalidTokenCount();

        // Verify all amounts are non-zero
        for (uint256 i = 0; i < n; ++i) {
            if (amounts[i] == 0) revert ZeroAmount();
        }

        if (totalSupply == 0) {
            // First deposit: accept any ratio
            // Transfer tokens in
            for (uint256 i = 0; i < n; ++i) {
                _safeTransferFrom(tokens[i], msg.sender, address(this), amounts[i]);
                reserves[i] = amounts[i];
            }

            // Compute initial invariant
            (uint256[] memory normalized,) =
                OrbitalMath.normalizeReserves(reserves, n);
            uint256 K = OrbitalMath.computeInvariant(normalized, concentration);

            // LP = K^(1/p) - MINIMUM_LIQUIDITY (burned to zero address)
            liquidity = OrbitalMath.wadRoot(K, concentration);
            if (liquidity <= MINIMUM_LIQUIDITY) revert InsufficientLiquidity();
            liquidity -= MINIMUM_LIQUIDITY;

            // Burn minimum liquidity to prevent share inflation attacks
            _mint(address(0), MINIMUM_LIQUIDITY);
        } else {
            // Subsequent deposits: must be proportional to current reserves
            // Find the minimum ratio across all tokens
            uint256 minRatio = type(uint256).max;
            for (uint256 i = 0; i < n; ++i) {
                uint256 ratio = (amounts[i] * WAD) / reserves[i];
                if (ratio < minRatio) minRatio = ratio;
            }

            // Transfer tokens proportionally and add to reserves
            for (uint256 i = 0; i < n; ++i) {
                uint256 actual = (reserves[i] * minRatio) / WAD;
                if (actual == 0) revert ZeroAmount();
                _safeTransferFrom(tokens[i], msg.sender, address(this), actual);
                reserves[i] += actual;
            }

            // Mint LP proportional to the ratio of increase
            liquidity = (totalSupply * minRatio) / WAD;
        }

        if (liquidity < minLiquidity) revert InsufficientLiquidity();
        _mint(msg.sender, liquidity);

        uint256[] memory depositedAmounts = new uint256[](n);
        for (uint256 i = 0; i < n; ++i) {
            depositedAmounts[i] = amounts[i];
        }
        emit LiquidityAdded(msg.sender, depositedAmounts, liquidity);
    }

    // ---------------------------------------------------------------
    //  Remove Liquidity
    // ---------------------------------------------------------------

    /**
     * @notice Remove liquidity from the pool, receiving proportional
     *         amounts of all tokens.
     *
     * @param liquidity   Number of LP tokens to burn.
     * @param minAmounts  Minimum amounts of each token to receive.
     * @param deadline    Transaction deadline.
     * @return amounts    Actual amounts of each token returned.
     */
    function removeLiquidity(
        uint256 liquidity,
        uint256[] calldata minAmounts,
        uint256 deadline
    ) external nonReentrant whenInitialized checkDeadline(deadline) returns (uint256[] memory amounts) {
        uint256 n = numTokens;
        if (minAmounts.length != n) revert InvalidTokenCount();
        if (liquidity == 0) revert ZeroAmount();
        if (balanceOf[msg.sender] < liquidity) revert InsufficientBalance();

        amounts = OrbitalMath.computeLiquidityBurn(reserves, liquidity, totalSupply);

        // Check minimums
        for (uint256 i = 0; i < n; ++i) {
            if (amounts[i] < minAmounts[i]) revert SlippageExceeded();
            if (amounts[i] == 0) revert ZeroAmount();
        }

        // Burn LP tokens
        _burn(msg.sender, liquidity);

        // Update reserves and transfer tokens out
        for (uint256 i = 0; i < n; ++i) {
            reserves[i] -= amounts[i];
            _safeTransfer(tokens[i], msg.sender, amounts[i]);
        }

        emit LiquidityRemoved(msg.sender, amounts, liquidity);
    }

    // ---------------------------------------------------------------
    //  View Functions
    // ---------------------------------------------------------------

    /// @notice Get the current reserves array.
    function getReserves() external view returns (uint256[] memory) {
        return reserves;
    }

    /// @notice Get the token addresses array.
    function getTokens() external view returns (address[] memory) {
        return tokens;
    }

    /// @notice Get the token index for a given token address.
    ///         Returns numTokens if not found.
    function getTokenIndex(address token) external view returns (uint256) {
        for (uint256 i = 0; i < numTokens; ++i) {
            if (tokens[i] == token) return i;
        }
        return numTokens; // Not found sentinel
    }

    /// @notice Get the accumulated fees array.
    function getAccumulatedFees() external view returns (uint256[] memory) {
        return accumulatedFees;
    }

    /**
     * @notice Get the expected output amount for a swap (view function).
     *
     * @param tokenInIndex  Index of input token.
     * @param tokenOutIndex Index of output token.
     * @param amountIn      Input amount.
     * @return amountOut    Expected output amount after fees.
     * @return feeAmount    Fee deducted from input.
     */
    function getAmountOut(
        uint256 tokenInIndex,
        uint256 tokenOutIndex,
        uint256 amountIn
    ) external view returns (uint256 amountOut, uint256 feeAmount) {
        if (tokenInIndex >= numTokens || tokenOutIndex >= numTokens) revert InvalidTokenIndex();
        if (tokenInIndex == tokenOutIndex) revert SameToken();
        if (amountIn == 0) revert ZeroAmount();

        feeAmount = (amountIn * swapFeeBps) / FEE_DENOMINATOR;
        uint256 amountInAfterFee = amountIn - feeAmount;

        uint256 n = numTokens;
        (uint256[] memory normalized, uint256 D) =
            OrbitalMath.normalizeReserves(reserves, n);

        uint256 dxNorm = (n * amountInAfterFee * WAD) / D;

        uint256 dyNorm = OrbitalMath.computeSwapOutput(
            normalized,
            tokenInIndex,
            tokenOutIndex,
            dxNorm,
            concentration
        );

        amountOut = (dyNorm * D) / (n * WAD);
    }

    /// @notice Get the current invariant K.
    function getInvariant() external view returns (uint256 K) {
        if (!initialized || totalSupply == 0) return 0;
        uint256 n = numTokens;
        (uint256[] memory normalized,) =
            OrbitalMath.normalizeReserves(reserves, n);
        K = OrbitalMath.computeInvariant(normalized, concentration);
    }

    /**
     * @notice Get the current spot price of tokenB in terms of tokenA.
     *         Spot price is the marginal exchange rate for an infinitesimal trade.
     *
     *         For the superellipse: price_A/B = (r_A / r_B)^(p-1)
     *
     * @param tokenAIndex Index of the numeraire token.
     * @param tokenBIndex Index of the priced token.
     * @return price WAD-scaled price (amount of tokenA per tokenB).
     */
    function getSpotPrice(
        uint256 tokenAIndex,
        uint256 tokenBIndex
    ) external view returns (uint256 price) {
        if (tokenAIndex >= numTokens || tokenBIndex >= numTokens) revert InvalidTokenIndex();
        if (reserves[tokenAIndex] == 0 || reserves[tokenBIndex] == 0) return 0;

        // Spot price = (rB / rA)^(p-1) for the superellipse
        // We compute this as rB^(p-1) / rA^(p-1)
        // In WAD: wadPow(rB_norm, p) / wadPow(rA_norm, p) * rA_norm / rB_norm
        // Simplified: (rB/rA)^(p-1) = rB^p / rA^p * rA / rB

        uint256 n = numTokens;
        (uint256[] memory normalized,) =
            OrbitalMath.normalizeReserves(reserves, n);

        uint256 xA = normalized[tokenAIndex];
        uint256 xB = normalized[tokenBIndex];

        if (concentration == 2) {
            // Price = xB / xA
            price = OrbitalMath.wadDiv(xB, xA);
        } else {
            // Price = (xB / xA)^(p-1)
            // Compute as xB^p / xA^p * xA / xB
            uint256 powA = OrbitalMath.wadPow(xA, concentration);
            uint256 powB = OrbitalMath.wadPow(xB, concentration);
            if (powA == 0) return 0;
            price = OrbitalMath.wadMul(
                OrbitalMath.wadDiv(powB, powA),
                OrbitalMath.wadDiv(xA, xB)
            );
        }
    }

    // ---------------------------------------------------------------
    //  Fee Collection
    // ---------------------------------------------------------------

    /// @notice Collect accumulated fees. Only callable by feeCollector.
    function collectFees() external nonReentrant {
        if (msg.sender != feeCollector) revert NotFactory();

        uint256 n = numTokens;
        uint256[] memory collected = new uint256[](n);

        for (uint256 i = 0; i < n; ++i) {
            uint256 amount = accumulatedFees[i];
            if (amount > 0) {
                accumulatedFees[i] = 0;
                collected[i] = amount;
                _safeTransfer(tokens[i], feeCollector, amount);
            }
        }

        emit FeesCollected(feeCollector, collected);
    }

    // ---------------------------------------------------------------
    //  LP Token (ERC-20 inline)
    // ---------------------------------------------------------------

    function transfer(address to, uint256 amount) external returns (bool) {
        if (to == address(0)) revert ZeroAddress();
        if (balanceOf[msg.sender] < amount) revert InsufficientBalance();
        unchecked { balanceOf[msg.sender] -= amount; }
        balanceOf[to] += amount;
        emit Transfer(msg.sender, to, amount);
        return true;
    }

    function approve(address spender, uint256 amount) external returns (bool) {
        if (spender == address(0)) revert ZeroAddress();
        allowance[msg.sender][spender] = amount;
        emit Approval(msg.sender, spender, amount);
        return true;
    }

    function transferFrom(address from, address to, uint256 amount) external returns (bool) {
        if (to == address(0)) revert ZeroAddress();
        if (balanceOf[from] < amount) revert InsufficientBalance();
        uint256 current = allowance[from][msg.sender];
        if (current != type(uint256).max) {
            if (current < amount) revert InsufficientAllowance();
            unchecked { allowance[from][msg.sender] = current - amount; }
        }
        unchecked { balanceOf[from] -= amount; }
        balanceOf[to] += amount;
        emit Transfer(from, to, amount);
        return true;
    }

    // ---------------------------------------------------------------
    //  Internal: LP mint/burn
    // ---------------------------------------------------------------

    function _mint(address to, uint256 amount) private {
        totalSupply += amount;
        balanceOf[to] += amount;
        emit Transfer(address(0), to, amount);
    }

    function _burn(address from, uint256 amount) private {
        if (balanceOf[from] < amount) revert InsufficientBalance();
        unchecked { balanceOf[from] -= amount; }
        totalSupply -= amount;
        emit Transfer(from, address(0), amount);
    }

    // ---------------------------------------------------------------
    //  Internal: Safe ERC-20 transfers
    // ---------------------------------------------------------------

    function _safeTransferFrom(
        address token,
        address from,
        address to,
        uint256 amount
    ) private {
        (bool success, bytes memory data) = token.call(
            abi.encodeWithSelector(0x23b872dd, from, to, amount)
        );
        if (!success || (data.length > 0 && !abi.decode(data, (bool)))) {
            revert TransferFailed();
        }
    }

    function _safeTransfer(address token, address to, uint256 amount) private {
        (bool success, bytes memory data) = token.call(
            abi.encodeWithSelector(0xa9059cbb, to, amount)
        );
        if (!success || (data.length > 0 && !abi.decode(data, (bool)))) {
            revert TransferFailed();
        }
    }
}

contracts/orbital/OrbitalRouter.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./OrbitalPool.sol";
import "./OrbitalFactory.sol";

/**
 * @title OrbitalRouter
 * @notice High-level router for interacting with OrbitalPool contracts.
 *
 *         Provides convenience functions for:
 *         - Token-address-based swaps (resolve token indices automatically)
 *         - Multi-hop swaps through multiple pools
 *         - Simplified liquidity management
 *         - Automatic token approvals
 *
 * @dev    Stateless router -- does not hold any tokens between calls.
 */

interface IERC20Router {
    function balanceOf(address account) external view returns (uint256);
    function transfer(address to, uint256 amount) external returns (bool);
    function allowance(address owner, address spender) external view returns (uint256);
    function approve(address spender, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
}

contract OrbitalRouter {

    // ---------------------------------------------------------------
    //  Storage
    // ---------------------------------------------------------------

    /// @notice The OrbitalFactory used to look up pools.
    OrbitalFactory public immutable orbitalFactory;

    // ---------------------------------------------------------------
    //  Events
    // ---------------------------------------------------------------

    event SwapExecuted(
        address indexed sender,
        address indexed pool,
        address tokenIn,
        address tokenOut,
        uint256 amountIn,
        uint256 amountOut
    );

    event LiquidityAdded(
        address indexed sender,
        address indexed pool,
        uint256 lpMinted
    );

    event LiquidityRemoved(
        address indexed sender,
        address indexed pool,
        uint256 lpBurned
    );

    // ---------------------------------------------------------------
    //  Errors
    // ---------------------------------------------------------------

    error PoolNotFound();
    error TokenNotInPool();
    error ZeroAmount();
    error SlippageExceeded();
    error TransferFailed();
    error DeadlineExpired();
    error InvalidPath();
    error InsufficientAllowance();

    // ---------------------------------------------------------------
    //  Constructor
    // ---------------------------------------------------------------

    constructor(address _factory) {
        orbitalFactory = OrbitalFactory(_factory);
    }

    // ---------------------------------------------------------------
    //  Swap Functions
    // ---------------------------------------------------------------

    /**
     * @notice Swap tokens through a specific pool by token addresses.
     *
     * @param pool          Address of the OrbitalPool.
     * @param tokenIn       Address of the input token.
     * @param tokenOut      Address of the output token.
     * @param amountIn      Amount of input token.
     * @param minAmountOut  Minimum output (slippage protection).
     * @param deadline      Transaction deadline.
     * @return amountOut    Actual output amount.
     */
    function swap(
        address pool,
        address tokenIn,
        address tokenOut,
        uint256 amountIn,
        uint256 minAmountOut,
        uint256 deadline
    ) external returns (uint256 amountOut) {
        if (block.timestamp > deadline) revert DeadlineExpired();
        if (amountIn == 0) revert ZeroAmount();

        OrbitalPool orbPool = OrbitalPool(pool);

        // Resolve token indices
        uint256 tokenInIndex = orbPool.getTokenIndex(tokenIn);
        uint256 tokenOutIndex = orbPool.getTokenIndex(tokenOut);
        if (tokenInIndex >= orbPool.numTokens()) revert TokenNotInPool();
        if (tokenOutIndex >= orbPool.numTokens()) revert TokenNotInPool();

        // Transfer tokens from user to this router
        _safeTransferFrom(tokenIn, msg.sender, address(this), amountIn);

        // Approve pool to spend tokens
        _ensureApproval(tokenIn, pool, amountIn);

        // Execute swap
        amountOut = orbPool.swap(
            tokenInIndex,
            tokenOutIndex,
            amountIn,
            minAmountOut,
            deadline
        );

        // Transfer output to user
        _safeTransfer(tokenOut, msg.sender, amountOut);

        emit SwapExecuted(msg.sender, pool, tokenIn, tokenOut, amountIn, amountOut);
    }

    /**
     * @notice Execute a multi-hop swap through a series of pools.
     *
     * @param pools         Array of pool addresses to route through.
     * @param tokenPath     Array of token addresses defining the path.
     *                      Length must be pools.length + 1.
     * @param amountIn      Initial input amount.
     * @param minAmountOut  Minimum final output.
     * @param deadline      Transaction deadline.
     * @return amountOut    Final output amount.
     */
    function swapMultiHop(
        address[] calldata pools,
        address[] calldata tokenPath,
        uint256 amountIn,
        uint256 minAmountOut,
        uint256 deadline
    ) external returns (uint256 amountOut) {
        if (block.timestamp > deadline) revert DeadlineExpired();
        if (pools.length == 0) revert InvalidPath();
        if (tokenPath.length != pools.length + 1) revert InvalidPath();
        if (amountIn == 0) revert ZeroAmount();

        // Transfer initial tokens from user
        _safeTransferFrom(tokenPath[0], msg.sender, address(this), amountIn);

        uint256 currentAmount = amountIn;

        for (uint256 i = 0; i < pools.length; ++i) {
            OrbitalPool orbPool = OrbitalPool(pools[i]);
            address tokenIn = tokenPath[i];
            address tokenOut = tokenPath[i + 1];

            uint256 tokenInIndex = orbPool.getTokenIndex(tokenIn);
            uint256 tokenOutIndex = orbPool.getTokenIndex(tokenOut);
            if (tokenInIndex >= orbPool.numTokens()) revert TokenNotInPool();
            if (tokenOutIndex >= orbPool.numTokens()) revert TokenNotInPool();

            // Approve pool
            _ensureApproval(tokenIn, pools[i], currentAmount);

            // Execute hop
            currentAmount = orbPool.swap(
                tokenInIndex,
                tokenOutIndex,
                currentAmount,
                0, // No intermediate slippage check
                deadline
            );
        }

        if (currentAmount < minAmountOut) revert SlippageExceeded();

        // Transfer final output to user
        _safeTransfer(tokenPath[tokenPath.length - 1], msg.sender, currentAmount);

        amountOut = currentAmount;
    }

    // ---------------------------------------------------------------
    //  Liquidity Functions
    // ---------------------------------------------------------------

    /**
     * @notice Add liquidity to a pool through the router.
     *
     * @param pool          Address of the OrbitalPool.
     * @param amounts       Token amounts to deposit.
     * @param minLiquidity  Minimum LP tokens to receive.
     * @param deadline      Transaction deadline.
     * @return liquidity    LP tokens minted.
     */
    function addLiquidity(
        address pool,
        uint256[] calldata amounts,
        uint256 minLiquidity,
        uint256 deadline
    ) external returns (uint256 liquidity) {
        if (block.timestamp > deadline) revert DeadlineExpired();

        OrbitalPool orbPool = OrbitalPool(pool);
        uint256 n = orbPool.numTokens();

        // Transfer tokens from user and approve pool
        for (uint256 i = 0; i < n; ++i) {
            address token = orbPool.tokens(i);
            if (amounts[i] > 0) {
                _safeTransferFrom(token, msg.sender, address(this), amounts[i]);
                _ensureApproval(token, pool, amounts[i]);
            }
        }

        // Add liquidity
        liquidity = orbPool.addLiquidity(amounts, minLiquidity, deadline);

        // Transfer LP tokens to user
        orbPool.transfer(msg.sender, liquidity);

        emit LiquidityAdded(msg.sender, pool, liquidity);
    }

    /**
     * @notice Remove liquidity from a pool through the router.
     *
     * @param pool          Address of the OrbitalPool.
     * @param liquidity     LP tokens to burn.
     * @param minAmounts    Minimum token amounts to receive.
     * @param deadline      Transaction deadline.
     * @return amounts      Actual amounts returned.
     */
    function removeLiquidity(
        address pool,
        uint256 liquidity,
        uint256[] calldata minAmounts,
        uint256 deadline
    ) external returns (uint256[] memory amounts) {
        if (block.timestamp > deadline) revert DeadlineExpired();
        if (liquidity == 0) revert ZeroAmount();

        OrbitalPool orbPool = OrbitalPool(pool);

        // Transfer LP tokens from user to this router
        orbPool.transferFrom(msg.sender, address(this), liquidity);

        // Remove liquidity
        amounts = orbPool.removeLiquidity(liquidity, minAmounts, deadline);

        // Transfer tokens to user
        uint256 n = orbPool.numTokens();
        for (uint256 i = 0; i < n; ++i) {
            if (amounts[i] > 0) {
                address token = orbPool.tokens(i);
                _safeTransfer(token, msg.sender, amounts[i]);
            }
        }

        emit LiquidityRemoved(msg.sender, pool, liquidity);
    }

    // ---------------------------------------------------------------
    //  View Functions
    // ---------------------------------------------------------------

    /**
     * @notice Get expected output for a swap on a specific pool.
     */
    function getAmountOut(
        address pool,
        address tokenIn,
        address tokenOut,
        uint256 amountIn
    ) external view returns (uint256 amountOut, uint256 feeAmount) {
        OrbitalPool orbPool = OrbitalPool(pool);
        uint256 tokenInIndex = orbPool.getTokenIndex(tokenIn);
        uint256 tokenOutIndex = orbPool.getTokenIndex(tokenOut);
        if (tokenInIndex >= orbPool.numTokens()) revert TokenNotInPool();
        if (tokenOutIndex >= orbPool.numTokens()) revert TokenNotInPool();

        (amountOut, feeAmount) = orbPool.getAmountOut(tokenInIndex, tokenOutIndex, amountIn);
    }

    /**
     * @notice Get expected output for a multi-hop swap.
     */
    function getAmountOutMultiHop(
        address[] calldata pools,
        address[] calldata tokenPath,
        uint256 amountIn
    ) external view returns (uint256 amountOut) {
        if (pools.length == 0) revert InvalidPath();
        if (tokenPath.length != pools.length + 1) revert InvalidPath();

        uint256 currentAmount = amountIn;
        for (uint256 i = 0; i < pools.length; ++i) {
            OrbitalPool orbPool = OrbitalPool(pools[i]);
            uint256 tokenInIndex = orbPool.getTokenIndex(tokenPath[i]);
            uint256 tokenOutIndex = orbPool.getTokenIndex(tokenPath[i + 1]);

            (currentAmount,) = orbPool.getAmountOut(tokenInIndex, tokenOutIndex, currentAmount);
        }
        amountOut = currentAmount;
    }

    // ---------------------------------------------------------------
    //  Internal
    // ---------------------------------------------------------------

    function _ensureApproval(address token, address spender, uint256 amount) private {
        uint256 current = IERC20Router(token).allowance(address(this), spender);
        if (current < amount) {
            // Reset to 0 first (for tokens like USDT that require this)
            if (current > 0) {
                (bool ok,) = token.call(
                    abi.encodeWithSelector(0x095ea7b3, spender, uint256(0))
                );
                if (!ok) revert TransferFailed();
            }
            (bool success,) = token.call(
                abi.encodeWithSelector(0x095ea7b3, spender, type(uint256).max)
            );
            if (!success) revert TransferFailed();
        }
    }

    function _safeTransferFrom(
        address token,
        address from,
        address to,
        uint256 amount
    ) private {
        (bool success, bytes memory data) = token.call(
            abi.encodeWithSelector(0x23b872dd, from, to, amount)
        );
        if (!success || (data.length > 0 && !abi.decode(data, (bool)))) {
            revert TransferFailed();
        }
    }

    function _safeTransfer(address token, address to, uint256 amount) private {
        (bool success, bytes memory data) = token.call(
            abi.encodeWithSelector(0xa9059cbb, to, amount)
        );
        if (!success || (data.length > 0 && !abi.decode(data, (bool)))) {
            revert TransferFailed();
        }
    }
}

contracts/security-token/interfaces/IDiv.content:
// SPDX-License-Identifier: MIT

pragma solidity ^0.8.4;



interface IDividends  {

  /************************
   * Functions
   ************************/

  /// @dev Get unused ERC-20 tokens on snapshot
  /// @param token ERC-20 token address
  /// @param snapshotId Snapshot ID
  /// @return amount of ERC-20 tokens
  function tokensAt(address token, uint256 snapshotId) external view returns (uint256);

  /// @dev Withdrawal remains of unused ERC-20 tokens at snapshot
  /// @param token ERC-20 token address
  /// @param snapshotId Snapshot ID
  function withdrawalRemains(address token, uint256 snapshotId) external;

  /**
   * @dev Fund any ERC-20 tokens into current contract
   * Tokens can be claimed by holders of RestrictedSwap Token uses claimDividends method
   * @param token ERC-20 token address
   * @param amount amount of tokens to fund
   * @param snapshotId snapshot ID of RestrictedSwap Token
   */
  function fundDividend(address token, uint256 amount, uint256 snapshotId) external;

  /**
   * @dev Get balance of ERC-20 tokens funded at snapshot
   * @param token ERC-20 token address
   * @param snapshotId snapshot ID of RestrictedSwap Token
   * @return amount of ERC-20 tokens
   */
  function fundsAt(address token, uint256 snapshotId) external view returns (uint256);

  /**
   * @dev Amount of ERC-20 tokens distributed to the holder of RestrictedSwap Token at snapshot
   * @param token ERC-20 token address
   * @param receiver RestrictedSwap Token's holder address
   * @param snapshotId snapshot ID of RestrictedSwap Token
   * @return amount of total ERC-20 tokens distributed to the receiver
   */
  function totalAwardedBalanceAt(address token, address receiver, uint256 snapshotId) external view returns (uint256);

  /**
   * @dev Amount of ERC-20 tokens claimed by the holder of RestrictedSwap Token at snapshot
   * @param token ERC-20 token address
   * @param receiver RestrictedSwap Token's holder address
   * @param snapshotId snapshot ID of RestrictedSwap Token
   * @return amount of claimed ERC-20 tokens
   */
  function claimedBalanceAt(address token, address receiver, uint256 snapshotId) external view returns (uint256);

  /**
   * @dev Amount of ERC-20 tokens that can be claimed by the holder of RestrictedSwap Token at snapshot
   * @param token ERC-20 token address
   * @param receiver RestrictedSwap Token's holder address
   * @param snapshotId snapshot ID of RestrictedSwap Token
   * @return amount of can be claimed ERC-20 tokens
   */
  function unclaimedBalanceAt(address token, address receiver, uint256 snapshotId) external view returns (uint256);

  /**
   * @dev Claim ERC-20 tokens (dividends) by RestrictedSwap Tokens holder
   * Tokens can be claimed when its allowed by unclaimedBalanceAt
   * @param token ERC-20 token address
   * @param snapshotId snapshot ID of RestrictedSwap Token
   */
  function claimDividend(address token, uint256 snapshotId) external;

  /****************************
   * Events
   ****************************/

  event Funded (address indexed payer, address indexed token, uint256 amount, uint256 indexed snapshotId);
  event Claimed (address indexed payee, address indexed token, uint256 amount, uint256 indexed snapshotId);
  event Withdrawn (address indexed payee, address indexed token, uint256 amount, uint256 indexed snapshotId);
}

